export enum View {
  COLLABORATOR = 'COLLABORATOR',
  DRIVER = 'DRIVER',
  ADMIN = 'ADMIN',
  ORDER = 'ORDER'
}

export enum TicketStatus {
  PENDING = 'Pendiente',
  IN_TRANSIT = 'En Tránsito',
  DELIVERED = 'Entregado',
  NOT_FOUND = 'No Encontrado',
  CANCELLED = 'Cancelado'
}

export interface Ticket {
  id: string;
  vendor: string;
  price: number;
  status: TicketStatus;
  zone: string;
  updatedAt: string;
  vehicle?: string;
  observations?: string;
  photoUrl?: string;
}

export interface Zone {
  id: string;
  name: string;
  price: number;
  estimatedTime: string;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

import React, { useState, useEffect } from 'react';

const OrderView: React.FC = () => {
  const [formData, setFormData] = useState({
    folio: '',
    ticketNo: '',
    clientName: '',
    phone: '',
    purchaseAmount: '',
    units: '',
    shippingCost: ''
  });

  // Generate Unique Folio on Mount
  useEffect(() => {
    generateNewFolio();
  }, []);

  const generateNewFolio = () => {
    const date = new Date();
    const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '');
    const randomId = Math.floor(1000 + Math.random() * 9000); // 4 digit random
    const newFolio = `FN-${dateStr}-${randomId}`;
    setFormData(prev => ({ ...prev, folio: newFolio }));
  };

  const handleChange = (field: string, value: string) => {
    // Validation Logic
    if (field === 'clientName') {
      // Only letters and spaces
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }

    if (field === 'phone' || field === 'units') {
      // Only numbers
      if (!/^\d*$/.test(value)) return;
    }

    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.ticketNo || !formData.clientName || !formData.phone) {
      alert("Por favor complete los campos obligatorios.");
      return;
    }

    // Simulate API save
    setTimeout(() => {
      alert(`✅ Pedido Registrado con Éxito\nFolio: ${formData.folio}\nCliente: ${formData.clientName}`);

      // Reset form but keep a new folio
      setFormData({
        folio: '',
        ticketNo: '',
        clientName: '',
        phone: '',
        purchaseAmount: '',
        units: '',
        shippingCost: ''
      });
      generateNewFolio();
    }, 500);
  };

  return (
    <div className="animate-fadeIn">
      <div className="bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-2xl mx-auto">
        <div className="flex items-center gap-4 mb-6 border-b border-gray-100 pb-4">
          <div className="p-3 bg-teal-100 text-teal-600 rounded-xl">
            <i className="fas fa-clipboard-list text-2xl"></i>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-800">Nuevo Pedido</h2>
            <p className="text-sm text-gray-500">Registro de ventas y envíos</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Folio Section */}
          <div className="bg-gray-50 p-4 rounded-xl border border-gray-200 flex justify-between items-center">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Folio Asignado (Auto)</label>
            <span className="text-lg font-mono font-black text-gray-700 tracking-wider">{formData.folio}</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            {/* Ticket No */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">No. Ticket</label>
              <div className="relative">
                <i className="fas fa-receipt absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.ticketNo}
                  onChange={(e) => handleChange('ticketNo', e.target.value)}
                  placeholder="A-12345"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-bold"
                />
              </div>
            </div>

            {/* Unidades */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Unidades</label>
              <div className="relative">
                <i className="fas fa-box absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  inputMode="numeric"
                  value={formData.units}
                  onChange={(e) => handleChange('units', e.target.value)}
                  placeholder="0"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-bold"
                />
              </div>
            </div>
          </div>

          {/* Nombre Cliente */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">Nombre del Cliente <span className="text-teal-500 text-[10px]">(Solo Letras)</span></label>
            <div className="relative">
              <i className="fas fa-user absolute left-4 top-4 text-gray-400"></i>
              <input 
                type="text" 
                value={formData.clientName}
                onChange={(e) => handleChange('clientName', e.target.value)}
                placeholder="Nombre Completo"
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-medium"
              />
            </div>
          </div>

          {/* Teléfono */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">Teléfono <span className="text-teal-500 text-[10px]">(Solo Números)</span></label>
            <div className="relative">
              <i className="fas fa-phone absolute left-4 top-4 text-gray-400"></i>
              <input 
                type="text" 
                inputMode="numeric"
                value={formData.phone}
                onChange={(e) => handleChange('phone', e.target.value)}
                placeholder="55 1234 5678"
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-bold tracking-wider"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-5 pt-2">
            {/* Monto Compra */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Monto de Compra</label>
              <div className="relative">
                <span className="absolute left-4 top-3 text-gray-400 font-bold">$</span>
                <input 
                  type="number" 
                  value={formData.purchaseAmount}
                  onChange={(e) => handleChange('purchaseAmount', e.target.value)}
                  placeholder="0.00"
                  className="w-full pl-8 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-bold text-gray-700"
                />
                <span className="absolute right-4 top-3 text-xs text-gray-400 font-bold">MXN</span>
              </div>
            </div>

            {/* Costo Envío */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Costo de Envío</label>
              <div className="relative">
                <span className="absolute left-4 top-3 text-gray-400 font-bold">$</span>
                <input 
                  type="number" 
                  value={formData.shippingCost}
                  onChange={(e) => handleChange('shippingCost', e.target.value)}
                  placeholder="0.00"
                  className="w-full pl-8 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-bold text-blue-600"
                />
                <span className="absolute right-4 top-3 text-xs text-gray-400 font-bold">MXN</span>
              </div>
            </div>
          </div>

          <div className="pt-4">
            <button 
              type="submit"
              className="w-full bg-gray-900 hover:bg-black text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-gray-200 transform active:scale-[0.98] flex items-center justify-center gap-2"
            >
              <i className="fas fa-check-circle"></i>
              Registrar Pedido
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default OrderView;

