const ShipmentView: React.FC = () => {
  const [formData, setFormData] = useState({
    folio: '',
    unit: '',
    plates: '',
    driver: ''
  });

  const [selectedOrder, setSelectedOrder] = useState<typeof ACTIVE_ORDERS[0] | null>(null);
  const [showReceipt, setShowReceipt] = useState(false);

  const handleChange = (field: string, value: string) => {
    // Validation Logic
    if (field === 'unit' || field === 'plates') {
      // Alphanumeric
      if (!/^[a-zA-Z0-9\s-]*$/.test(value)) return;
    }

    if (field === 'driver') {
      // Letters only
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }

    setFormData(prev => ({ ...prev, [field]: value }));

    // If folio changes, find the order details
    if (field === 'folio') {
      const order = ACTIVE_ORDERS.find(o => o.folio === value);
      setSelectedOrder(order || null);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.folio || !formData.unit || !formData.plates || !formData.driver) {
      alert("Todos los campos son obligatorios");
      return;
    }
    // Show receipt modal
    setShowReceipt(true);
  };

  const handlePrint = () => {
    window.print();
  };

  const closeReceipt = () => {
    setShowReceipt(false);
    setFormData({ folio: '', unit: '', plates: '', driver: '' });
    setSelectedOrder(null);
  };

  return (
    <div className="animate-fadeIn">
      {/* --- Main Form UI --- */}
      <div className={`bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-2xl mx-auto ${showReceipt ? 'hidden md:block opacity-50 pointer-events-none' : ''}`}>
        <div className="flex items-center gap-4 mb-6 border-b border-gray-100 pb-4">
