            <i className="fas fa-shipping-fast text-2xl"></i>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-800">Generar Embarque</h2>
            <p className="text-sm text-gray-500">Asignación de unidad y chofer</p>
          </div>
        </div>

        <form onSubmit={handleSave} className="space-y-5">
          {/* Folio Selection */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">Seleccionar Folio Activo</label>
            <div className="relative">
              <i className="fas fa-list-ol absolute left-4 top-4 text-gray-400"></i>
              <select 
                value={formData.folio}
                onChange={(e) => handleChange('folio', e.target.value)}
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-purple-500 focus:ring-0 outline-none transition-all font-bold bg-white appearance-none"
              >
                <option value="">-- Seleccione un Pedido --</option>
                {ACTIVE_ORDERS.map(order => (
                  <option key={order.folio} value={order.folio}>
                    {order.folio} - {order.client}
                  </option>
                ))}
              </select>
            </div>
            {selectedOrder && (
               <p className="text-xs text-green-600 font-bold ml-2 mt-1">
                 <i className="fas fa-check-circle mr-1"></i> 
                 Destino: {selectedOrder.address}
               </p>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            {/* Unit */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Unidad (Vehículo)</label>
              <div className="relative">
                <i className="fas fa-truck-pickup absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.unit}
                  onChange={(e) => handleChange('unit', e.target.value)}
                  placeholder="Ejem: Nissan NP300"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-purple-500 focus:ring-0 outline-none transition-all font-bold uppercase"
                />
