            </button>
            <button 
              onClick={closeReceipt}
              className="bg-red-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-red-700 transition-colors"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>

          {/* Actual Receipt Content */}
          <div id="print-area" className="bg-white p-4 w-[300px] text-black font-mono text-sm shadow-2xl print:shadow-none print:w-full print:max-w-[80mm] print:mx-0 print:p-0">
            <div className="text-center mb-4 border-b-2 border-dashed border-black pb-2">
              <h1 className="font-bold text-xl">FERRENICO LOGISTICA</h1>
              <p className="text-xs">Jilotepec de Molina Enríquez</p>
              <p className="text-xs">Tel: 55 1234 5678</p>
              <p className="mt-2 font-bold">EMBARQUE DE MERCANCIA</p>
            </div>

            <div className="mb-4 space-y-1 text-xs">
              <div className="flex justify-between">
                <span>FECHA:</span>
                <span>{new Date().toLocaleDateString()}</span>
              </div>
