const ShipmentView: React.FC = () => {
  const [formData, setFormData] = useState({
    folio: '',
    unit: '',
    plates: '',
    driver: ''
  });

  const [selectedOrder, setSelectedOrder] = useState<typeof ACTIVE_ORDERS[0] | null>(null);
  const [showReceipt, setShowReceipt] = useState(false);

  const handleChange = (field: string, value: string) => {
    // Validation Logic
    if (field === 'unit' || field === 'plates') {
      // Alphanumeric
      if (!/^[a-zA-Z0-9\s-]*$/.test(value)) return;
    }

    if (field === 'driver') {
      // Letters only
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }

    setFormData(prev => ({ ...prev, [field]: value }));

    // If folio changes, find the order details
    if (field === 'folio') {
      const order = ACTIVE_ORDERS.find(o => o.folio === value);
      setSelectedOrder(order || null);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.folio || !formData.unit || !formData.plates || !formData.driver) {
      alert("Todos los campos son obligatorios");
      return;
    }
    // Show receipt modal
    setShowReceipt(true);
  };

  const handlePrint = () => {
    window.print();
  };

  const closeReceipt = () => {
    setShowReceipt(false);
    setFormData({ folio: '', unit: '', plates: '', driver: '' });
    setSelectedOrder(null);
  };

  return (
    <div className="animate-fadeIn">
      {/* --- Main Form UI --- */}
      <div className={`bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-2xl mx-auto ${showReceipt ? 'hidden md:block opacity-50 pointer-events-none' : ''}`}>
        <div className="flex items-center gap-4 mb-6 border-b border-gray-100 pb-4">
          <div className="p-3 bg-purple-100 text-purple-600 rounded-xl">
            <i className="fas fa-shipping-fast text-2xl"></i>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-800">Generar Embarque</h2>
            <p className="text-sm text-gray-500">Asignación de unidad y chofer</p>
          </div>
        </div>

        <form onSubmit={handleSave} className="space-y-5">
          {/* Folio Selection */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">Seleccionar Folio Activo</label>
            <div className="relative">
              <i className="fas fa-list-ol absolute left-4 top-4 text-gray-400"></i>
              <select 
                value={formData.folio}
                onChange={(e) => handleChange('folio', e.target.value)}
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-purple-500 focus:ring-0 outline-none transition-all font-bold bg-white appearance-none"
              >
                <option value="">-- Seleccione un Pedido --</option>
                {ACTIVE_ORDERS.map(order => (
                  <option key={order.folio} value={order.folio}>
                    {order.folio} - {order.client}
                  </option>
                ))}
              </select>
            </div>
            {selectedOrder && (
               <p className="text-xs text-green-600 font-bold ml-2 mt-1">
                 <i className="fas fa-check-circle mr-1"></i> 
                 Destino: {selectedOrder.address}
               </p>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            {/* Unit */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Unidad (Vehículo)</label>
              <div className="relative">
                <i className="fas fa-truck-pickup absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.unit}
                  onChange={(e) => handleChange('unit', e.target.value)}
                  placeholder="Ejem: Nissan NP300"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-purple-500 focus:ring-0 outline-none transition-all font-bold uppercase"
                />
              </div>
            </div>

            {/* Plates */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Placas</label>
              <div className="relative">
                <i className="fas fa-minus-circle absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.plates}
                  onChange={(e) => handleChange('plates', e.target.value)}
                  placeholder="ABC-123-D"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-purple-500 focus:ring-0 outline-none transition-all font-bold uppercase"
                />
              </div>
            </div>
          </div>

          {/* Driver */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">Nombre del Chofer <span className="text-purple-500 text-[10px]">(Solo Letras)</span></label>
            <div className="relative">
              <i className="fas fa-user-friends absolute left-4 top-4 text-gray-400"></i>
              <input 
                type="text" 
                value={formData.driver}
                onChange={(e) => handleChange('driver', e.target.value)}
                placeholder="Nombre Completo del Operador"
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-purple-500 focus:ring-0 outline-none transition-all font-medium"
              />
            </div>
          </div>

          <div className="pt-4">
            <button 
              type="submit"
              className="w-full bg-purple-900 hover:bg-purple-950 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-purple-200 transform active:scale-[0.98] flex items-center justify-center gap-2"
            >
              <i className="fas fa-print"></i>
              Guardar y Generar Ticket
            </button>
          </div>
        </form>
      </div>

      {/* --- Receipt Modal / Printable Area --- */}
      {showReceipt && selectedOrder && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4 print:p-0 print:bg-white print:static print:block">

          {/* Modal Actions (Hidden on Print) */}
          <div className="absolute top-4 right-4 flex gap-2 print:hidden">
            <button 
              onClick={handlePrint}
              className="bg-white text-black font-bold py-2 px-4 rounded-lg hover:bg-gray-200 transition-colors"
            >
              <i className="fas fa-print mr-2"></i> Imprimir
            </button>
            <button 
              onClick={closeReceipt}
              className="bg-red-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-red-700 transition-colors"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>

          {/* Actual Receipt Content */}
          <div id="print-area" className="bg-white p-4 w-[300px] text-black font-mono text-sm shadow-2xl print:shadow-none print:w-full print:max-w-[80mm] print:mx-0 print:p-0">
            <div className="text-center mb-4 border-b-2 border-dashed border-black pb-2">
              <h1 className="font-bold text-xl">FERRENICO LOGISTICA</h1>
              <p className="text-xs">Jilotepec de Molina Enríquez</p>
              <p className="text-xs">Tel: 55 1234 5678</p>
              <p className="mt-2 font-bold">EMBARQUE DE MERCANCIA</p>
            </div>

            <div className="mb-4 space-y-1 text-xs">
              <div className="flex justify-between">
                <span>FECHA:</span>
                <span>{new Date().toLocaleDateString()}</span>
              </div>
              <div className="flex justify-between">
                <span>FOLIO:</span>
                <span className="font-bold">{formData.folio}</span>
              </div>
              <div className="flex justify-between">
                <span>UNIDAD:</span>
                <span>{formData.unit}</span>
              </div>
              <div className="flex justify-between">
                <span>CHOFER:</span>
                <span>{formData.driver}</span>
              </div>
            </div>

            <div className="border-t border-b border-black py-2 mb-4">
              <p className="font-bold mb-1">DATOS DE ENTREGA:</p>
              <p className="uppercase">{selectedOrder.client}</p>
              <p className="mb-1">Tel: {selectedOrder.phone}</p>
              <p className="text-xs uppercase break-words">{selectedOrder.address}</p>
            </div>

            <div className="space-y-1 text-right mb-4">
               <div className="flex justify-between">
                <span>UNIDADES:</span>
                <span>{selectedOrder.units} pzs</span>
              </div>
              <div className="flex justify-between">
                <span>SUBTOTAL:</span>
                <span>${selectedOrder.amount.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>ENVIO:</span>
                <span>${selectedOrder.shipping.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-lg font-bold border-t border-dashed border-black pt-1 mt-1">
                <span>TOTAL:</span>
                <span>${(selectedOrder.amount + selectedOrder.shipping).toFixed(2)}</span>
              </div>
            </div>

            {/* Signature Area */}
            <div className="mt-16 mb-6">
              <div className="border-t-2 border-black w-3/4 mx-auto"></div>
              <p className="text-center text-xs font-bold mt-1">NOMBRE Y FIRMA DE RECIBIDO</p>
            </div>

            <div className="text-center text-xs mt-6 border-t border-black pt-2">
              <p>*** GRACIAS POR SU PREFERENCIA ***</p>
              <p>Conserve este ticket para cualquier aclaración.</p>
            </div>
          </div>
        </div>
      )}

      {/* Print Specific Styles */}
      <style>{`
        @media print {
          body * {
            visibility: hidden;
          }
          #print-area, #print-area * {
            visibility: visible;
          }
          #print-area {
            position: absolute;
            left: 0;
            top: 0;
            width: 80mm;
            padding: 0;
            margin: 0;
          }
          @page {
            size: 80mm auto;
            margin: 0;
          }
        }
      `}</style>
    </div>
  );
};

