const OrderView: React.FC = () => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    ticketNo: '',
    vendorNo: '', // Note: DB doesn't have vendor column, we won't save this specifically or append to another field if needed
    clientName: '',
    deliveryAddress: '', // Note: DB doesn't have address, we will append to clientName
    phone: '',
    purchaseAmount: '',
    units: '',
    shippingCost: ''
  });

  const handleChange = (field: string, value: string) => {
    // Validation Logic
    if (field === 'clientName') {
      // Only letters and spaces
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }

    if (field === 'phone' || field === 'units') {
      // Only numbers
      if (!/^\d*$/.test(value)) return;
    }

    if (field === 'vendorNo') {
      // Only numbers and max 4 chars
      if (!/^\d*$/.test(value)) return;
      if (value.length > 4) return;
    }

    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.ticketNo || !formData.clientName || !formData.phone || !formData.deliveryAddress) {
      alert("Por favor complete los campos obligatorios.");
      return;
    }

    setIsSubmitting(true);

    try {
      // Prepare data for Supabase 'pedido' table
      // Since DB lacks address, we combine Client Name + Address
      const fullClientName = `${formData.clientName} | ${formData.deliveryAddress}`;

      const { data, error } = await supabase
        .from('pedido')
        .insert([
          {
            no_tiket: formData.ticketNo,
            nombre_cliente: fullClientName,
            telefono: formData.phone,
            monto_de_compra: parseFloat(formData.purchaseAmount) || 0,
            unidades: parseInt(formData.units) || 0,
            costo_de_envio: parseFloat(formData.shippingCost) || 0,
            estado: TicketStatus.PENDING
          }
        ])
        .select();

      if (error) throw error;

      const createdOrder = data[0];

      alert(`✅ Pedido Registrado en Supabase\nFolio UUID: ${createdOrder.folio}\nEstatus Inicial: PENDIENTE`);

      // Reset form
      setFormData({
        ticketNo: '',
        vendorNo: '',
        clientName: '',
        deliveryAddress: '',
        phone: '',
        purchaseAmount: '',
        units: '',
        shippingCost: ''
      });

    } catch (error: any) {
      console.error('Error creating order:', error);
      alert('Error al guardar el pedido: ' + error.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="animate-fadeIn">
      <div className="bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-2xl mx-auto">
