            <p className="text-sm text-gray-500">Registro en Base de Datos</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Folio Section */}
          <div className="bg-gray-50 p-4 rounded-xl border border-gray-200 flex justify-between items-center">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Folio (Generado por Sistema)</label>
            <span className="text-sm font-mono font-bold text-gray-500 tracking-wider">Se asignará al guardar</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
            {/* Ticket No */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">No. Ticket</label>
              <div className="relative">
                <i className="fas fa-receipt absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.ticketNo}
                  onChange={(e) => handleChange('ticketNo', e.target.value)}
                  placeholder="A-12345"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-teal-500 focus:ring-0 outline-none transition-all font-bold"
                />
              </div>
            </div>

            {/* Vendor No (Optional for display, won't save to DB directly as no column) */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">No. Vendedor</label>
              <div className="relative">
                <i className="fas fa-id-badge absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
