                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold"
                />
              </div>
            </div>

            {/* Phone */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Teléfono</label>
              <div className="relative">
                <i className="fas fa-phone absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.phone}
                  onChange={(e) => handleChange('phone', e.target.value)}
