                    {order.no_tiket} - {order.nombre_cliente.substring(0, 25)}...
                  </option>
                ))}
              </select>
            </div>
            {selectedOrder && (
               <p className="text-xs text-blue-600 font-bold ml-2 mt-1 break-words">
                 <i className="fas fa-check-circle mr-1"></i> 
                 Cliente: {selectedOrder.nombre_cliente}
               </p>
