I'm now implementing the `OrderView` component, focusing on the state management for the success modal. The code includes `isSubmitting` for the loading state and `lastCreatedOrder` to hold the details of the newly created order. I'll need to link the modal visibility to this state. The focus is ensuring the success modal correctly reflects a successful new order.

```tsx
import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { TicketStatus, Pedido } from '../types'; // Import Pedido for type safety

const OrderView: React.FC = () => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [lastCreatedOrder, setLastCreatedOrder] = useState<Pedido | null>(null); // State for success modal
  const [showSuccessModal, setShowSuccessModal] = useState(false); // State for success modal visibility

  const [formData, setFormData] = useState({
    ticketNo: '',
    vendorNo: '',
    clientName: '',
    deliveryAddress: '',
    phone: '',
    purchaseAmount: '',
    units: '',
    shippingCost: ''
  });

  // ... handleChange ...

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.ticketNo || !formData.clientName || !formData.phone || !formData.deliveryAddress) {
      alert("Por favor complete los campos obligatorios.");
      return
    }

    setIsSubmitting(true);
    try {
      const { data, error } = await supabase
        .from('pedidos')
        .insert([{
          ticket_no: formData.ticketNo,
          vendor_no: formData.vendorNo,
          client_name: formData.clientName,
          delivery_address: formData.deliveryAddress,
          phone: formData.phone,
          purchase_amount: parseFloat(formData.purchaseAmount),
          units: parseInt(formData.units),
          shipping_cost: parseFloat(formData.shippingCost),
          status: TicketStatus.CREATED // Assuming an enum or constant for statuses
        }])
        .select('*');

      if (error) {
        throw error;
      }

      if (data && data.length > 0) {
          setLastCreatedOrder(data[0] as Pedido);
          setShowSuccessModal(true);
          setFormData({
              ticketNo: '',
              vendorNo: '',
              clientName: '',
              deliveryAddress: '',
              phone: '',
              purchaseAmount: '',
              units: '',
              shippingCost: ''
          });
      }
    } catch (error) {
      console.error('Error creating order:', error);
      alert('Hubo un error al crear el pedido. Por favor, intente de nuevo.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    // ... form and modal rendering ...
  );
};

export default OrderView;
```

