          /* Target specifically the shipment view wrapper */
          #root > div {
             display: block !important;
          }
          /* Hide the form container explicitly */
          #root > div > div:not(#print-area) {
             display: none !important;
          }

          /* Show the print area */
          #print-area {
            display: block !important;
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            margin: 0;
            padding: 0;
            background-color: white;
            font-family: 'Courier New', Courier, monospace;
            color: black;
          }

          /* Epson m244a / Standard Thermal Printer Settings (80mm) */
          @page {
            size: 80mm auto; /* continuous roll */
            margin: 0;
          }

          /* Remove browser headers/footers */
          html, body {
            margin: 0;
            padding: 0;
          }
        }
      `}</style>
    </div>
  );
