import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';

const ShipmentView: React.FC = () => {
  const [activeOrders, setActiveOrders] = useState<Pedido[]>([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    folio: '',
    unit: '',
    plates: '',
    driver: ''
  });

  // Stores the order to be printed (hidden from view, visible only to printer)
  const [printOrder, setPrintOrder] = useState<Pedido | null>(null);

  // Fetch pending orders on mount
  useEffect(() => {
    fetchPendingOrders();
  }, []);

  const fetchPendingOrders = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('pedido')
        .select('*')
        .eq('estado', TicketStatus.PENDING);

      if (error) throw error;
      if (data) setActiveOrders(data);
    } catch (error) {
      console.error("Error fetching orders:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field: string, value: string) => {
    if (field === 'unit' || field === 'plates') {
      if (!/^[a-zA-Z0-9\s-]*$/.test(value)) return;
    }

    if (field === 'driver') {
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }

    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.folio || !formData.unit || !formData.plates || !formData.driver) {
      alert("Todos los campos son obligatorios");
      return;
    }

    try {
      // Find the order object before updating, to use for printing
      const orderToPrint = activeOrders.find(o => o.folio === formData.folio);
      if (!orderToPrint) {
        alert("Error: No se encontró la información del pedido para imprimir.");
        return;
      }

      // 1. Update Pedido Status in Supabase
      const { error: updateError } = await supabase
        .from('pedido')
        .update({ estado: TicketStatus.IN_TRANSIT })
        .eq('folio', formData.folio);

      if (updateError) throw updateError;

      // 2. Insert into Embarque table
      const { error: insertError } = await supabase
        .from('embarque')
        .insert([
          {
            unidad: formData.unit,
            placas: formData.plates,
            chofer: formData.driver
          }
        ]);

      if (insertError) throw insertError;

      // 3. Prepare for Printing
      // Inject form data into the print object so it appears on the ticket
      setPrintOrder({
        ...orderToPrint,
        tempUnit: formData.unit,
        tempDriver: formData.driver
      });

      // Clear form inputs immediately so user knows it finished
      setFormData({ folio: '', unit: '', plates: '', driver: '' });
      fetchPendingOrders();

      // 4. Trigger Print Dialog
      // We use a timeout to ensure React has rendered the #print-area with the new data
      setTimeout(() => {
        if (window.confirm("¿Está seguro de que desea imprimir el recibo?")) {
          window.print();
        }
      }, 600);

    } catch (error: any) {
      console.error("Error saving shipment:", error);
      alert("Error al guardar el embarque: " + error.message);
    }
  };

  return (
    <div className="animate-fadeIn">
      {/* --- Main Form UI (Visible on Screen, Hidden on Print) --- */}
      <div className="screen-only bg-white p-6 rounded-2xl shadow-xl border-t-4 border-blue-800 max-w-2xl mx-auto">
        <div className="flex items-center gap-4 mb-6 border-b border-gray-100 pb-4">
          <div className="p-3 bg-blue-50 text-blue-800 rounded-xl">
            <i className="fas fa-shipping-fast text-2xl"></i>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-800">Generar Embarque</h2>
            <p className="text-sm text-gray-500">Asignación de unidad y chofer</p>
          </div>
        </div>

        <form onSubmit={handleSave} className="space-y-5">
          {/* Folio Selection */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">
              Seleccionar Pedido Pendiente {loading && <i className="fas fa-spinner fa-spin ml-2"></i>}
            </label>
            <div className="relative">
              <i className="fas fa-list-ol absolute left-4 top-4 text-gray-400"></i>
              <select 
                value={formData.folio}
                onChange={(e) => handleChange('folio', e.target.value)}
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold bg-white appearance-none"
              >
                <option value="">-- Seleccione un Pedido --</option>
                {activeOrders.map(order => (
                  <option key={order.folio} value={order.folio}>
                    {order.no_tiket} - {order.nombre_cliente.substring(0, 25)}...
                  </option>
                ))}
              </select>
            </div>
            {formData.folio && activeOrders.find(o => o.folio === formData.folio) && (
               <p className="text-xs text-blue-600 font-bold ml-2 mt-1 break-words">
                 <i className="fas fa-check-circle mr-1"></i> 
                 Cliente: {activeOrders.find(o => o.folio === formData.folio)?.nombre_cliente}
               </p>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            {/* Unit */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Unidad (Vehículo)</label>
              <div className="relative">
                <i className="fas fa-truck-pickup absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.unit}
                  onChange={(e) => handleChange('unit', e.target.value)}
                  placeholder="Ejem: Nissan NP300"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold uppercase"
                />
              </div>
            </div>

            {/* Plates */}
            <div className="space-y-1">
              <label className="block text-xs font-bold text-gray-600 uppercase">Placas</label>
              <div className="relative">
                <i className="fas fa-minus-circle absolute left-4 top-4 text-gray-400"></i>
                <input 
                  type="text" 
                  value={formData.plates}
                  onChange={(e) => handleChange('plates', e.target.value)}
                  placeholder="ABC-123-D"
                  className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold uppercase"
                />
              </div>
            </div>
          </div>

          {/* Driver */}
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-600 uppercase">Nombre del Chofer <span className="text-blue-500 text-[10px]">(Solo Letras)</span></label>
            <div className="relative">
              <i className="fas fa-user-friends absolute left-4 top-4 text-gray-400"></i>
              <input 
                type="text" 
                value={formData.driver}
                onChange={(e) => handleChange('driver', e.target.value)}
                placeholder="Nombre Completo del Operador"
                className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-medium"
              />
            </div>
          </div>

          <div className="pt-4">
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-blue-200 transform active:scale-[0.98] flex items-center justify-center gap-2 border-b-4 border-blue-950"
            >
              <i className="fas fa-print"></i>
              Guardar y Generar Ticket
            </button>
          </div>
        </form>
      </div>

      {/* --- Print Area (Hidden on Screen, Visible on Print) --- */}
      {printOrder && (
        <div id="print-area" className="hidden">
           <div className="text-center mb-4 border-b-2 border-dashed border-black pb-2">
            <h1 className="font-bold text-xl">FERRE DON NICO</h1>
            <p className="text-xs">Jilotepec de Molina Enríquez</p>
            <p className="mt-2 font-bold text-sm">EMBARQUE DE MERCANCIA</p>
          </div>

          <div className="mb-4 space-y-1 text-xs font-mono">
            <div className="flex justify-between">
              <span>FECHA:</span>
              <span>{new Date().toLocaleDateString()}</span>
            </div>
             <div className="flex justify-between">
              <span>FOLIO:</span>
              <span className="font-bold">{printOrder.folio.slice(0,8)}</span>
            </div>
            <div className="flex justify-between">
              <span>TICKET:</span>
              <span className="font-bold text-sm">{printOrder.no_tiket}</span>
            </div>
             <div className="flex justify-between">
              <span>UNIDAD:</span>
              <span className="uppercase">{printOrder.tempUnit || "N/A"}</span>
            </div>
            <div className="flex justify-between">
              <span>CHOFER:</span>
              <span className="uppercase">{printOrder.tempDriver || "N/A"}</span>
            </div>
            <div className="flex justify-between border-t border-dotted border-black pt-1 mt-1">
              <span>ESTATUS:</span>
              <span className="font-bold">EN TRÁNSITO</span>
            </div>
          </div>

           <div className="border-t border-b border-black py-2 mb-4">
            <p className="font-bold mb-1 text-xs">DATOS DE ENTREGA:</p>
            <p className="uppercase text-xs leading-tight">{printOrder.nombre_cliente}</p>
            <p className="mt-1 text-xs">Tel: {printOrder.telefono}</p>
          </div>

          <div className="space-y-1 text-right mb-4 text-xs font-mono">
              <div className="flex justify-between">
              <span>UNIDADES:</span>
              <span>{printOrder.unidades} pzs</span>
            </div>
            <div className="flex justify-between">
              <span>SUBTOTAL:</span>
              <span>${printOrder.monto_de_compra.toFixed(2)}</span>
            </div>
            <div className="flex justify-between">
              <span>ENVIO:</span>
              <span>${printOrder.costo_de_envio.toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-sm font-bold border-t border-dashed border-black pt-1 mt-1">
              <span>TOTAL:</span>
              <span>${(printOrder.monto_de_compra + printOrder.costo_de_envio).toFixed(2)}</span>
            </div>
          </div>

           <div className="mt-12 mb-6">
            <div className="border-t-2 border-black w-3/4 mx-auto"></div>
            <p className="text-center text-xs font-bold mt-1">FIRMA DE RECIBIDO</p>
          </div>

          <div className="text-center text-[10px] mt-6 border-t border-black pt-2">
            <p>*** GRACIAS POR SU PREFERENCIA ***</p>
          </div>
        </div>
      )}

      <style>{`
        @media print {
          /* Hide all screen-only elements */
          .screen-only {
            display: none !important;
          }

          /* Hide the main wrapper's other children if necessary, but targeting screen-only is cleaner */
          body > * {
            display: none !important;
          }

          /* Show root (parent of app) */
          body > #root {
            display: block !important;
          }

          /* Hide everything inside root by default */
          #root * {
            display: none !important;
          }

          /* Explicitly show the print area and its children */
          #root #print-area, #root #print-area * {
            display: block !important;
            visibility: visible !important;
          }

          #print-area {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            margin: 0;
            padding: 0;
            background-color: white;
            font-family: 'Courier New', Courier, monospace;
            color: black;
          }

          @page {
            size: 80mm auto;
            margin: 0;
          }
        }
      `}</style>
    </div>
  );
};

