                    onChange={(e) => handleChange('driver', e.target.value)}
                    placeholder="Nombre Completo del Operador"
                    className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-medium"
                  />
