      {printOrder && (
        <div id="print-container" className="hidden">
           {/* Inner content for PDF and Print */}
          <div 
            id="ticket-content"
            className="w-[80mm] mx-auto bg-white p-2 font-mono text-black"
          >
            <div className="text-center mb-4 border-b-2 border-dashed border-black pb-2">
              <h1 className="font-bold text-xl uppercase">Ferre Don Nico</h1>
