import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const AdminView: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [tickets, setTickets] = useState<Pedido[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [editingTicket, setEditingTicket] = useState<Pedido | null>(null);

  useEffect(() => {
    if (isLoggedIn) {
      fetchTickets();
    }
  }, [isLoggedIn]);

  const fetchTickets = async () => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('pedido')
      .select('*')
      .order('created_at', { ascending: false });

    if (data) setTickets(data as Pedido[]);
    setIsLoading(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'FerreNico25') {
      setIsLoggedIn(true);
    } else {
      alert("Clave de administrador incorrecta");
    }
  };

  const updateTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTicket) return;

    const { error } = await supabase
      .from('pedido')
      .update({ 
        estado: editingTicket.estado,
        no_tiket: editingTicket.no_tiket,
        monto_de_compra: editingTicket.monto_de_compra
      })
      .eq('folio', editingTicket.folio);

    if (!error) {
      alert("Datos actualizados correctamente.");
      setEditingTicket(null);
      fetchTickets();
    } else {
      alert("Error al actualizar: " + error.message);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case TicketStatus.DELIVERED: return 'bg-green-100 text-green-700 border-green-200';
      case TicketStatus.IN_TRANSIT: return 'bg-blue-100 text-blue-700 border-blue-200';
      case TicketStatus.PENDING: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case TicketStatus.NOT_FOUND: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const chartData = [
    { name: 'Entregados', value: tickets.filter(t => t.estado === TicketStatus.DELIVERED).length },
    { name: 'En Tránsito', value: tickets.filter(t => t.estado === TicketStatus.IN_TRANSIT).length },
    { name: 'Pendientes', value: tickets.filter(t => t.estado === TicketStatus.PENDING).length },
    { name: 'Incidencias', value: tickets.filter(t => t.estado === TicketStatus.NOT_FOUND).length },
  ];

  // Colors: Green (Success), Blue (Brand), Amber (Pending), Red (Error)
  const COLORS = ['#16a34a', '#1e40af', '#ca8a04', '#dc2626'];

  if (!isLoggedIn) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-fadeIn">
        <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-2xl border-t-4 border-blue-800">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-blue-800 text-white rounded-2xl mb-4">
              <i className="fas fa-lock text-2xl"></i>
            </div>
            <h2 className="text-2xl font-black text-gray-800">Acceso Restringido</h2>
            <p className="text-gray-500">Ingrese su clave de administrador</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-blue-800 focus:ring-0 text-center text-2xl tracking-widest outline-none transition-all"
              autoFocus
            />
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg transform active:scale-95 border-b-4 border-blue-950"
            >
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      {isLoading && <p className="text-center text-gray-500">Cargando datos de Supabase...</p>}

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {chartData.map((item, i) => (
          <div key={item.name} className={`bg-white p-4 rounded-2xl shadow-sm border-l-4`} style={{ borderLeftColor: COLORS[i] }}>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{item.name}</p>
            <p className="text-2xl font-black">{item.value}</p>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
            <i className="fas fa-list-check text-blue-800"></i>
            Bitácora de Pedidos
          </h3>
          <button 
            onClick={fetchTickets}
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 px-4 py-2 rounded-lg text-sm font-bold transition-colors"
          >
            <i className="fas fa-sync mr-2"></i>Actualizar
          </button>
        </div>
        <div className="overflow-x-auto -mx-6">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
              <tr>
                <th className="px-6 py-4">Folio (UUID)</th>
                <th className="px-6 py-4">Ticket</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {tickets.map((ticket) => (
                <tr key={ticket.folio} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-6 py-4 font-mono text-xs text-gray-400">{ticket.folio.substring(0,8)}...</td>
                  <td className="px-6 py-4 font-black text-gray-900">{ticket.no_tiket}</td>
                  <td className="px-6 py-4 text-gray-600 font-medium text-xs">{ticket.nombre_cliente.substring(0,30)}</td>
                  <td className="px-6 py-4 text-gray-500 text-xs">${ticket.monto_de_compra}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${getStatusColor(ticket.estado)}`}>
                      {ticket.estado}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => setEditingTicket({ ...ticket })}
                      className="text-blue-800 hover:text-blue-900 p-2 rounded-lg hover:bg-blue-100 transition-all shadow-sm border border-blue-100"
                      title="Editar Pedido"
                    >
                      <i className="fas fa-edit"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Stats Summary Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-gray-800">
          <i className="fas fa-chart-pie text-red-600"></i>
          Resumen Logístico
        </h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
              <XAxis type="number" hide />
              <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={100} />
              <Tooltip 
                cursor={{fill: 'transparent'}}
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} 
              />
              <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={40}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Edit Modal */}
      {editingTicket && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-slideUp">
            <div className="bg-blue-800 text-white p-6 flex justify-between items-center">
              <div>
                <h4 className="text-xl font-black">Editar Pedido</h4>
                <p className="text-blue-200 text-xs">Modificando: {editingTicket.no_tiket}</p>
              </div>
              <button onClick={() => setEditingTicket(null)} className="text-blue-300 hover:text-white transition-colors">
                <i className="fas fa-times text-2xl"></i>
              </button>
            </div>

            <form onSubmit={updateTicket} className="p-6 space-y-4">

              {/* Ticket No Input */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">No. Ticket</label>
                <input 
                  type="text" 
                  value={editingTicket.no_tiket}
                  onChange={e => setEditingTicket({ ...editingTicket, no_tiket: e.target.value })}
                  className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all font-bold"
                />
              </div>

              {/* Amount Input */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Monto de Compra</label>
                <div className="relative">
                  <span className="absolute left-3 top-3 text-gray-400 font-bold">$</span>
                  <input 
                    type="number" 
                    value={editingTicket.monto_de_compra}
                    onChange={e => setEditingTicket({ ...editingTicket, monto_de_compra: parseFloat(e.target.value) || 0 })}
                    className="w-full pl-8 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all font-bold"
                  />
                </div>
              </div>

              {/* Status Select */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Estado del Pedido</label>
                <div className="relative">
                  <select 
                    value={editingTicket.estado}
                    onChange={e => setEditingTicket({ ...editingTicket, estado: e.target.value })}
                    className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all appearance-none bg-white font-medium"
                  >
                    <option value={TicketStatus.PENDING}>Pendiente</option>
                    <option value={TicketStatus.IN_TRANSIT}>En Tránsito</option>
                    <option value={TicketStatus.DELIVERED}>Entregado</option>
                    <option value={TicketStatus.NOT_FOUND}>No Encontrado</option>
                  </select>
                  <i className="fas fa-chevron-down absolute right-4 top-4 text-gray-400 pointer-events-none"></i>
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="button"
                  onClick={() => setEditingTicket(null)}
                  className="flex-1 py-3 px-4 bg-gray-100 text-gray-600 font-bold rounded-xl hover:bg-gray-200 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 px-4 bg-blue-800 text-white font-bold rounded-xl hover:bg-blue-900 shadow-lg shadow-blue-200 transition-all"
                >
                  Guardar Cambios
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';

const ShipmentView: React.FC = () => {
  const [activeOrders, setActiveOrders] = useState<Pedido[]>([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    folio: '',
    unit: '',
    plates: '',
    driver: ''
  });

  // Stores the order to be printed
  const [printOrder, setPrintOrder] = useState<Pedido | null>(null);
  // Controls if we show the success/action panel instead of the form
  const [showActions, setShowActions] = useState(false);

  // Fetch pending orders on mount and subscribe to changes
  useEffect(() => {
    fetchPendingOrders();

    const channel = supabase
      .channel('pedido-updates')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'pedido' },
        () => fetchPendingOrders()
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const fetchPendingOrders = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('pedido')
        .select('*')
        .eq('estado', TicketStatus.PENDING)
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (data) setActiveOrders(data);
    } catch (error) {
      console.error("Error fetching orders:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field: string, value: string) => {
    if (field === 'unit' || field === 'plates') {
      if (!/^[a-zA-Z0-9\s-]*$/.test(value)) return;
    }
    if (field === 'driver') {
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.folio || !formData.unit || !formData.plates || !formData.driver) {
      alert("Todos los campos son obligatorios");
      return;
    }

    try {
      const orderToPrint = activeOrders.find(o => o.folio === formData.folio);
      if (!orderToPrint) {
        alert("Error: No se encontró la información del pedido para imprimir.");
        return;
      }

      const { error: updateError } = await supabase
        .from('pedido')
        .update({ estado: TicketStatus.IN_TRANSIT })
        .eq('folio', formData.folio);

      if (updateError) throw updateError;

      const { error: insertError } = await supabase
        .from('embarque')
        .insert([{
            unidad: formData.unit,
            placas: formData.plates,
            chofer: formData.driver
        }]);

      if (insertError) throw insertError;

      setPrintOrder({
        ...orderToPrint,
        tempUnit: formData.unit,
        tempDriver: formData.driver
      });

      setFormData({ folio: '', unit: '', plates: '', driver: '' });
      setShowActions(true);
      fetchPendingOrders();

    } catch (error: any) {
      console.error("Error saving shipment:", error);
      alert("Error al guardar el embarque: " + error.message);
    }
  };

  const handleDownloadPDF = () => {
    if (!printOrder) return;

    // Use the specific ID of the ticket content container
    const element = document.getElementById('ticket-content');
    if (!element) {
      alert("No se encontró el ticket para generar PDF");
      return;
    }

    // Access html2pdf from window (loaded via script tag in index.html)
    // @ts-ignore
    const html2pdf = window.html2pdf;

    if (!html2pdf) {
      alert("Librería PDF no cargada. Por favor recargue la página.");
      return;
    }

    // Make visible temporarily for capture if needed, though html2canvas usually handles hidden nodes if configured right.
    // However, to be safe with all browsers, we clone or rely on existing state. 
    // Since previous state worked for user, we keep it simple.

    const opt = {
      margin: 2,
      filename: `Embarque_${printOrder.no_tiket}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: [80, 200], orientation: 'portrait' }
    };

    html2pdf().set(opt).from(element).save();
  };

  const handleNewShipment = () => {
    setPrintOrder(null);
    setShowActions(false);
  };

  return (
    <div className="animate-fadeIn pb-10">

      {/* UI WRAPPER */}
      <div id="shipment-ui">
        {!showActions ? (
          /* --- Main Form UI --- */
          <div className="bg-white p-6 rounded-2xl shadow-xl border-t-4 border-blue-800 max-w-2xl mx-auto">
            <div className="flex items-center gap-4 mb-6 border-b border-gray-100 pb-4">
              <div className="p-3 bg-blue-50 text-blue-800 rounded-xl">
                <i className="fas fa-shipping-fast text-2xl"></i>
              </div>
              <div>
                <h2 className="text-2xl font-black text-gray-800">Generar Embarque</h2>
                <p className="text-sm text-gray-500">Asignación de unidad y chofer</p>
              </div>
            </div>

            <form onSubmit={handleSave} className="space-y-5">
              {/* Folio Selection */}
              <div className="space-y-1">
                <label className="block text-xs font-bold text-gray-600 uppercase">
                  Seleccionar Pedido Pendiente {loading && <i className="fas fa-spinner fa-spin ml-2"></i>}
                </label>
                <div className="relative">
                  <i className="fas fa-list-ol absolute left-4 top-4 text-gray-400"></i>
                  <select 
                    value={formData.folio}
                    onChange={(e) => handleChange('folio', e.target.value)}
                    className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold bg-white appearance-none"
                  >
                    <option value="">-- Seleccione un Pedido --</option>
                    {activeOrders.map(order => (
                      <option key={order.folio} value={order.folio}>
                        {order.no_tiket} - {order.nombre_cliente.substring(0, 25)}...
                      </option>
                    ))}
                  </select>
                </div>
                {formData.folio && activeOrders.find(o => o.folio === formData.folio) && (
                  <p className="text-xs text-blue-600 font-bold ml-2 mt-1 break-words">
                    <i className="fas fa-check-circle mr-1"></i> 
                    Cliente: {activeOrders.find(o => o.folio === formData.folio)?.nombre_cliente}
                  </p>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                {/* Unit */}
                <div className="space-y-1">
                  <label className="block text-xs font-bold text-gray-600 uppercase">Unidad (Vehículo)</label>
                  <div className="relative">
                    <i className="fas fa-truck-pickup absolute left-4 top-4 text-gray-400"></i>
                    <input 
                      type="text" 
                      value={formData.unit}
                      onChange={(e) => handleChange('unit', e.target.value)}
                      placeholder="Ejem: Nissan NP300"
                      className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold uppercase"
                    />
                  </div>
                </div>

                {/* Plates */}
                <div className="space-y-1">
                  <label className="block text-xs font-bold text-gray-600 uppercase">Placas</label>
                  <div className="relative">
                    <i className="fas fa-minus-circle absolute left-4 top-4 text-gray-400"></i>
                    <input 
                      type="text" 
                      value={formData.plates}
                      onChange={(e) => handleChange('plates', e.target.value)}
                      placeholder="ABC-123-D"
                      className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold uppercase"
                    />
                  </div>
                </div>
              </div>

              {/* Driver */}
              <div className="space-y-1">
                <label className="block text-xs font-bold text-gray-600 uppercase">Nombre del Chofer <span className="text-blue-500 text-[10px]">(Solo Letras)</span></label>
                <div className="relative">
                  <i className="fas fa-user-friends absolute left-4 top-4 text-gray-400"></i>
                  <input 
                    type="text" 
                    value={formData.driver}
                    onChange={(e) => handleChange('driver', e.target.value)}
                    placeholder="Nombre Completo del Operador"
                    className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-medium"
                  />
                </div>
              </div>

              <div className="pt-4">
                <button 
                  type="submit"
                  className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-blue-200 transform active:scale-[0.98] flex items-center justify-center gap-2 border-b-4 border-blue-950"
                >
                  <i className="fas fa-check-circle"></i>
                  Generar y Guardar Embarque
                </button>
              </div>
            </form>
          </div>
        ) : (
          /* --- Action Panel (After Success) --- */
          <div className="animate-fadeIn max-w-md mx-auto">
            <div className="bg-white rounded-3xl shadow-2xl p-8 border-t-8 border-green-500 text-center">
              <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                <i className="fas fa-check text-4xl text-green-600"></i>
              </div>

              <h3 className="text-2xl font-black text-gray-800 mb-2">¡Embarque Generado!</h3>
              <p className="text-gray-500 mb-6 text-sm">El pedido ha pasado a estado <strong>"En Tránsito"</strong>.</p>

              <div className="space-y-3">
                <button 
                  onClick={handleDownloadPDF}
                  className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2"
                >
                  <i className="fas fa-file-pdf"></i>
                  Descargar PDF
                </button>

                <div className="border-t border-gray-100 my-4 pt-4">
                  <button 
                    onClick={handleNewShipment}
                    className="w-full bg-white border-2 border-gray-200 hover:bg-gray-50 text-gray-600 font-bold py-3 rounded-xl transition-all"
                  >
                    <i className="fas fa-plus mr-2"></i>
                    Nuevo Embarque
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* --- Print Container --- */}
      {/* Hidden container, used as source for html2pdf */}
      {printOrder && (
        <div id="print-container" className="hidden">
           {/* Inner content for PDF */}
          <div 
            id="ticket-content"
            className="w-[80mm] mx-auto bg-white p-2 font-mono text-black"
          >
            <div className="text-center mb-4 border-b-2 border-dashed border-black pb-2">
              <h1 className="font-bold text-xl uppercase">Ferre Don Nico</h1>
              <p className="text-[10px] mt-1">Jilotepec de Molina Enríquez</p>
              <p className="mt-2 font-black text-sm border-2 border-black inline-block px-2 py-1">EMBARQUE DE SALIDA</p>
            </div>

            <div className="mb-4 space-y-1 text-[10px] leading-relaxed">
              <div className="flex justify-between">
                <span>FECHA:</span>
                <span>{new Date().toLocaleDateString()} {new Date().toLocaleTimeString()}</span>
              </div>
              <div className="flex justify-between">
                <span>FOLIO INT:</span>
                <span className="font-bold">{printOrder.folio.slice(0,8)}</span>
              </div>
              <div className="flex justify-between">
                <span>TICKET NO:</span>
                <span className="font-bold text-sm">{printOrder.no_tiket}</span>
              </div>
              <div className="flex justify-between border-t border-dotted border-black pt-1 mt-1">
                <span>UNIDAD:</span>
                <span className="uppercase font-bold">{printOrder.tempUnit || "N/A"}</span>
              </div>
              <div className="flex justify-between">
                <span>CHOFER:</span>
                <span className="uppercase font-bold">{printOrder.tempDriver || "N/A"}</span>
              </div>
            </div>

            <div className="border-t border-b border-black py-2 mb-4">
              <p className="font-bold mb-1 text-[10px] uppercase bg-black text-white inline-block px-1">DATOS DE ENTREGA:</p>
              <p className="uppercase text-[11px] leading-tight font-bold mt-1">{printOrder.nombre_cliente}</p>
              <p className="mt-1 text-[11px] font-bold"><i className="fas fa-phone mr-1"></i> Tel: {printOrder.telefono}</p>
            </div>

            <div className="space-y-1 text-right mb-4 text-[10px] font-mono">
                <div className="flex justify-between">
                <span>UNIDADES:</span>
                <span>{printOrder.unidades} pzs</span>
              </div>
              <div className="flex justify-between">
                <span>SUBTOTAL:</span>
                <span>${printOrder.monto_de_compra.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>ENVIO:</span>
                <span>${printOrder.costo_de_envio.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-sm font-black border-t-2 border-black pt-1 mt-1">
                <span>TOTAL A COBRAR:</span>
                <span>${(printOrder.monto_de_compra + printOrder.costo_de_envio).toFixed(2)}</span>
              </div>
            </div>

            <div className="mt-8 mb-6 text-center">
              <div className="h-16 mb-2 border-b border-black"></div>
              <p className="text-[9px] font-bold uppercase">Firma de Recibido / Sello</p>
            </div>

            <div className="text-center text-[9px] mt-4 border-t border-black pt-2">
              <p className="font-bold">*** FERRE DON NICO ***</p>
              <p>Gracias por su preferencia</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ShipmentView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const AdminView: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [tickets, setTickets] = useState<Pedido[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [editingTicket, setEditingTicket] = useState<Pedido | null>(null);

  // Estados para reporte
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetchTickets();
      // Set default dates for report (current month)
      const date = new Date();
      const firstDay = new Date(date.getFullYear(), date.getMonth(), 1).toISOString().split('T')[0];
      const currentDay = date.toISOString().split('T')[0];
      setStartDate(firstDay);
      setEndDate(currentDay);
    }
  }, [isLoggedIn]);

  const fetchTickets = async () => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('pedido')
      .select('*')
      .order('created_at', { ascending: false });

    if (data) setTickets(data as Pedido[]);
    setIsLoading(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'FerreNico25') {
      setIsLoggedIn(true);
    } else {
      alert("Clave de administrador incorrecta");
    }
  };

  const updateTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTicket) return;

    const { error } = await supabase
      .from('pedido')
      .update({ 
        estado: editingTicket.estado,
        no_tiket: editingTicket.no_tiket,
        monto_de_compra: editingTicket.monto_de_compra
      })
      .eq('folio', editingTicket.folio);

    if (!error) {
      alert("Datos actualizados correctamente.");
      setEditingTicket(null);
      fetchTickets();
    } else {
      alert("Error al actualizar: " + error.message);
    }
  };

  const deleteTicket = async (folio: string) => {
    if (window.confirm("¿Está seguro de que desea ELIMINAR este pedido permanentemente? Esta acción no se puede deshacer.")) {
      try {
        const { error } = await supabase
          .from('pedido')
          .delete()
          .eq('folio', folio);

        if (error) throw error;

        alert("Pedido eliminado correctamente.");
        fetchTickets();
      } catch (error: any) {
        console.error("Error al eliminar:", error);
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  const generateReport = async () => {
    if (!startDate || !endDate) {
      alert("Por favor seleccione ambas fechas.");
      return;
    }

    setIsGeneratingReport(true);
    try {
      // Fetch data based on range (inclusive)
      // Adjust endDate to include the full day (23:59:59) logic or just compare dates
      const { data, error } = await supabase
        .from('pedido')
        .select('*')
        .gte('created_at', `${startDate}T00:00:00`)
        .lte('created_at', `${endDate}T23:59:59`)
        .order('created_at', { ascending: true });

      if (error) throw error;

      if (!data || data.length === 0) {
        alert("No se encontraron registros en ese rango de fechas.");
        setIsGeneratingReport(false);
        return;
      }

      // Generate CSV content
      const headers = ["Fecha", "Ticket", "Cliente", "Direccion", "Telefono", "Unidades", "Estado", "Monto Compra", "Costo Envio", "Total"];

      const csvRows = data.map(order => {
        const date = new Date(order.created_at || '').toLocaleDateString();
        // Clean strings to avoid CSV breakage
        const cleanName = order.nombre_cliente.split('|')[0]?.trim() || '';
        const cleanAddress = (order.nombre_cliente.split('|')[1]?.trim() || order.nombre_cliente).replace(/,/g, ' '); 
        const total = (order.monto_de_compra + order.costo_de_envio).toFixed(2);

        return [
          date,
          order.no_tiket,
          cleanName,
          cleanAddress,
          order.telefono,
          order.unidades,
          order.estado,
          order.monto_de_compra,
          order.costo_de_envio,
          total
        ].join(',');
      });

      const csvContent = "data:text/csv;charset=utf-8," 
        + headers.join(',') + "\n" 
        + csvRows.join('\n');

      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `Reporte_FerreNico_${startDate}_al_${endDate}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

    } catch (error: any) {
      console.error("Error generating report:", error);
      alert("Error generando el reporte: " + error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case TicketStatus.DELIVERED: return 'bg-green-100 text-green-700 border-green-200';
      case TicketStatus.IN_TRANSIT: return 'bg-blue-100 text-blue-700 border-blue-200';
      case TicketStatus.PENDING: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case TicketStatus.NOT_FOUND: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const chartData = [
    { name: 'Entregados', value: tickets.filter(t => t.estado === TicketStatus.DELIVERED).length },
    { name: 'En Tránsito', value: tickets.filter(t => t.estado === TicketStatus.IN_TRANSIT).length },
    { name: 'Pendientes', value: tickets.filter(t => t.estado === TicketStatus.PENDING).length },
    { name: 'Incidencias', value: tickets.filter(t => t.estado === TicketStatus.NOT_FOUND).length },
  ];

  // Colors: Green (Success), Blue (Brand), Amber (Pending), Red (Error)
  const COLORS = ['#16a34a', '#1e40af', '#ca8a04', '#dc2626'];

  if (!isLoggedIn) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-fadeIn">
        <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-2xl border-t-4 border-blue-800">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-blue-800 text-white rounded-2xl mb-4">
              <i className="fas fa-lock text-2xl"></i>
            </div>
            <h2 className="text-2xl font-black text-gray-800">Acceso Restringido</h2>
            <p className="text-gray-500">Ingrese su clave de administrador</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-blue-800 focus:ring-0 text-center text-2xl tracking-widest outline-none transition-all"
              autoFocus
            />
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg transform active:scale-95 border-b-4 border-blue-950"
            >
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      {isLoading && <p className="text-center text-gray-500">Cargando datos de Supabase...</p>}

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {chartData.map((item, i) => (
          <div key={item.name} className={`bg-white p-4 rounded-2xl shadow-sm border-l-4`} style={{ borderLeftColor: COLORS[i] }}>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{item.name}</p>
            <p className="text-2xl font-black">{item.value}</p>
          </div>
        ))}
      </div>

      {/* Report Generator Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800 mb-4">
          <i className="fas fa-file-excel text-green-600"></i>
          Generador de Reportes
        </h3>
        <div className="flex flex-col md:flex-row items-end gap-4">
          <div className="w-full md:w-auto">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Inicio</label>
            <input 
              type="date" 
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium"
            />
          </div>
          <div className="w-full md:w-auto">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Fin</label>
            <input 
              type="date" 
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium"
            />
          </div>
          <button 
            onClick={generateReport}
            disabled={isGeneratingReport}
            className="w-full md:w-auto px-6 py-2.5 bg-green-600 hover:bg-green-700 text-white font-bold rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
          >
            {isGeneratingReport ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-download"></i>}
            Descargar Excel
          </button>
        </div>
      </div>

      {/* Table Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
            <i className="fas fa-list-check text-blue-800"></i>
            Bitácora de Pedidos
          </h3>
          <button 
            onClick={fetchTickets}
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 px-4 py-2 rounded-lg text-sm font-bold transition-colors"
          >
            <i className="fas fa-sync mr-2"></i>Actualizar
          </button>
        </div>
        <div className="overflow-x-auto -mx-6">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
              <tr>
                <th className="px-6 py-4">Folio (UUID)</th>
                <th className="px-6 py-4">Ticket</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {tickets.map((ticket) => (
                <tr key={ticket.folio} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-6 py-4 font-mono text-xs text-gray-400">{ticket.folio.substring(0,8)}...</td>
                  <td className="px-6 py-4 font-black text-gray-900">{ticket.no_tiket}</td>
                  <td className="px-6 py-4 text-gray-600 font-medium text-xs">{ticket.nombre_cliente.substring(0,30)}</td>
                  <td className="px-6 py-4 text-gray-500 text-xs">${ticket.monto_de_compra}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${getStatusColor(ticket.estado)}`}>
                      {ticket.estado}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right flex justify-end gap-2">
                    <button 
                      onClick={() => setEditingTicket({ ...ticket })}
                      className="text-blue-800 hover:text-blue-900 p-2 rounded-lg hover:bg-blue-100 transition-all shadow-sm border border-blue-100"
                      title="Editar Pedido"
                    >
                      <i className="fas fa-edit"></i>
                    </button>
                    <button 
                      onClick={() => deleteTicket(ticket.folio)}
                      className="text-red-500 hover:text-red-700 p-2 rounded-lg hover:bg-red-50 transition-all shadow-sm border border-red-100"
                      title="Eliminar Pedido"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Stats Summary Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-gray-800">
          <i className="fas fa-chart-pie text-red-600"></i>
          Resumen Logístico
        </h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
              <XAxis type="number" hide />
              <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={100} />
              <Tooltip 
                cursor={{fill: 'transparent'}}
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} 
              />
              <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={40}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Edit Modal */}
      {editingTicket && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-slideUp">
            <div className="bg-blue-800 text-white p-6 flex justify-between items-center">
              <div>
                <h4 className="text-xl font-black">Editar Pedido</h4>
                <p className="text-blue-200 text-xs">Modificando: {editingTicket.no_tiket}</p>
              </div>
              <button onClick={() => setEditingTicket(null)} className="text-blue-300 hover:text-white transition-colors">
                <i className="fas fa-times text-2xl"></i>
              </button>
            </div>

            <form onSubmit={updateTicket} className="p-6 space-y-4">

              {/* Ticket No Input */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">No. Ticket</label>
                <input 
                  type="text" 
                  value={editingTicket.no_tiket}
                  onChange={e => setEditingTicket({ ...editingTicket, no_tiket: e.target.value })}
                  className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all font-bold"
                />
              </div>

              {/* Amount Input */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Monto de Compra</label>
                <div className="relative">
                  <span className="absolute left-3 top-3 text-gray-400 font-bold">$</span>
                  <input 
                    type="number" 
                    value={editingTicket.monto_de_compra}
                    onChange={e => setEditingTicket({ ...editingTicket, monto_de_compra: parseFloat(e.target.value) || 0 })}
                    className="w-full pl-8 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all font-bold"
                  />
                </div>
              </div>

              {/* Status Select */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Estado del Pedido</label>
                <div className="relative">
                  <select 
                    value={editingTicket.estado}
                    onChange={e => setEditingTicket({ ...editingTicket, estado: e.target.value })}
                    className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all appearance-none bg-white font-medium"
                  >
                    <option value={TicketStatus.PENDING}>Pendiente</option>
                    <option value={TicketStatus.IN_TRANSIT}>En Tránsito</option>
                    <option value={TicketStatus.DELIVERED}>Entregado</option>
                    <option value={TicketStatus.NOT_FOUND}>No Encontrado</option>
                  </select>
                  <i className="fas fa-chevron-down absolute right-4 top-4 text-gray-400 pointer-events-none"></i>
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="button"
                  onClick={() => setEditingTicket(null)}
                  className="flex-1 py-3 px-4 bg-gray-100 text-gray-600 font-bold rounded-xl hover:bg-gray-200 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 px-4 bg-blue-800 text-white font-bold rounded-xl hover:bg-blue-900 shadow-lg shadow-blue-200 transition-all"
                >
                  Guardar Cambios
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Extended interface to handle joined data locally
interface ExtendedPedido extends Pedido {
  embarque?: { unidad: string; placas: string; chofer: string }[];
  evidencias_entrega?: { evidencia_fotografica: string; created_at: string }[];
}

const AdminView: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [tickets, setTickets] = useState<ExtendedPedido[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [editingTicket, setEditingTicket] = useState<ExtendedPedido | null>(null);
  const [viewingTicket, setViewingTicket] = useState<ExtendedPedido | null>(null);

  // Estados para reporte
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetchTickets();
      // Set default dates for report (current month)
      const date = new Date();
      const firstDay = new Date(date.getFullYear(), date.getMonth(), 1).toISOString().split('T')[0];
      const currentDay = date.toISOString().split('T')[0];
      setStartDate(firstDay);
      setEndDate(currentDay);
    }
  }, [isLoggedIn]);

  const fetchTickets = async () => {
    setIsLoading(true);
    // Fetch orders with related shipment and evidence info
    const { data, error } = await supabase
      .from('pedido')
      .select(`
        *,
        embarque ( unidad, placas, chofer ),
        evidencias_entrega ( evidencia_fotografica, created_at )
      `)
      .order('created_at', { ascending: false });

    if (data) setTickets(data as ExtendedPedido[]);
    setIsLoading(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'FerreNico25') {
      setIsLoggedIn(true);
    } else {
      alert("Clave de administrador incorrecta");
    }
  };

  const updateTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTicket) return;

    const { error } = await supabase
      .from('pedido')
      .update({ 
        estado: editingTicket.estado,
        no_tiket: editingTicket.no_tiket,
        monto_de_compra: editingTicket.monto_de_compra
      })
      .eq('folio', editingTicket.folio);

    if (!error) {
      alert("Datos actualizados correctamente.");
      setEditingTicket(null);
      fetchTickets();
    } else {
      alert("Error al actualizar: " + error.message);
    }
  };

  const deleteTicket = async (folio: string) => {
    if (window.confirm("¿Está seguro de que desea ELIMINAR este pedido permanentemente? Esta acción no se puede deshacer.")) {
      try {
        const { error } = await supabase
          .from('pedido')
          .delete()
          .eq('folio', folio);

        if (error) throw error;

        alert("Pedido eliminado correctamente.");
        fetchTickets();
      } catch (error: any) {
        console.error("Error al eliminar:", error);
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  const generateReport = async () => {
    if (!startDate || !endDate) {
      alert("Por favor seleccione ambas fechas.");
      return;
    }

    setIsGeneratingReport(true);
    try {
      // Include joined data in report fetch
      const { data, error } = await supabase
        .from('pedido')
        .select(`
          *,
          embarque ( unidad, placas, chofer )
        `)
        .gte('created_at', `${startDate}T00:00:00`)
        .lte('created_at', `${endDate}T23:59:59`)
        .order('created_at', { ascending: true });

      if (error) throw error;

      if (!data || data.length === 0) {
        alert("No se encontraron registros en ese rango de fechas.");
        setIsGeneratingReport(false);
        return;
      }

      // Generate CSV content with extra fields
      const headers = ["Fecha", "Ticket", "Cliente", "Direccion", "Telefono", "Unidades", "Estado", "Monto Compra", "Costo Envio", "Total", "Chofer", "Unidad", "Placas"];

      const csvRows = (data as ExtendedPedido[]).map(order => {
        const date = new Date(order.created_at || '').toLocaleDateString();
        const cleanName = order.nombre_cliente.split('|')[0]?.trim() || '';
        const cleanAddress = (order.nombre_cliente.split('|')[1]?.trim() || order.nombre_cliente).replace(/,/g, ' '); 
        const total = (order.monto_de_compra + order.costo_de_envio).toFixed(2);

        // Extract logistics info (assuming 1 shipment per order usually)
        const shipment = order.embarque && order.embarque.length > 0 ? order.embarque[0] : { chofer: '', unidad: '', placas: '' };

        return [
          date,
          order.no_tiket,
          cleanName,
          cleanAddress,
          order.telefono,
          order.unidades,
          order.estado,
          order.monto_de_compra,
          order.costo_de_envio,
          total,
          shipment.chofer,
          shipment.unidad,
          shipment.placas
        ].join(',');
      });

      const csvContent = "data:text/csv;charset=utf-8," 
        + headers.join(',') + "\n" 
        + csvRows.join('\n');

      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `Reporte_Logistica_FerreNico_${startDate}_al_${endDate}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

    } catch (error: any) {
      console.error("Error generating report:", error);
      alert("Error generando el reporte: " + error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case TicketStatus.DELIVERED: return 'bg-green-100 text-green-700 border-green-200';
      case TicketStatus.IN_TRANSIT: return 'bg-blue-100 text-blue-700 border-blue-200';
      case TicketStatus.PENDING: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case TicketStatus.NOT_FOUND: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const chartData = [
    { name: 'Entregados', value: tickets.filter(t => t.estado === TicketStatus.DELIVERED).length },
    { name: 'En Tránsito', value: tickets.filter(t => t.estado === TicketStatus.IN_TRANSIT).length },
    { name: 'Pendientes', value: tickets.filter(t => t.estado === TicketStatus.PENDING).length },
    { name: 'Incidencias', value: tickets.filter(t => t.estado === TicketStatus.NOT_FOUND).length },
  ];

  const COLORS = ['#16a34a', '#1e40af', '#ca8a04', '#dc2626'];

  if (!isLoggedIn) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-fadeIn">
        <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-2xl border-t-4 border-blue-800">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-blue-800 text-white rounded-2xl mb-4">
              <i className="fas fa-lock text-2xl"></i>
            </div>
            <h2 className="text-2xl font-black text-gray-800">Acceso Restringido</h2>
            <p className="text-gray-500">Ingrese su clave de administrador</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-blue-800 focus:ring-0 text-center text-2xl tracking-widest outline-none transition-all"
              autoFocus
            />
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg transform active:scale-95 border-b-4 border-blue-950"
            >
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      {isLoading && <p className="text-center text-gray-500">Cargando datos de Supabase...</p>}

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {chartData.map((item, i) => (
          <div key={item.name} className={`bg-white p-4 rounded-2xl shadow-sm border-l-4`} style={{ borderLeftColor: COLORS[i] }}>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{item.name}</p>
            <p className="text-2xl font-black">{item.value}</p>
          </div>
        ))}
      </div>

      {/* Report Generator Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800 mb-4">
          <i className="fas fa-file-excel text-green-600"></i>
          Generador de Reportes (Logística Completa)
        </h3>
        <div className="flex flex-col md:flex-row items-end gap-4">
          <div className="w-full md:w-auto">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Inicio</label>
            <input 
              type="date" 
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium"
            />
          </div>
          <div className="w-full md:w-auto">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Fin</label>
            <input 
              type="date" 
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium"
            />
          </div>
          <button 
            onClick={generateReport}
            disabled={isGeneratingReport}
            className="w-full md:w-auto px-6 py-2.5 bg-green-600 hover:bg-green-700 text-white font-bold rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
          >
            {isGeneratingReport ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-download"></i>}
            Descargar Excel
          </button>
        </div>
      </div>

      {/* Table Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
            <i className="fas fa-list-check text-blue-800"></i>
            Bitácora de Pedidos
          </h3>
          <button 
            onClick={fetchTickets}
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 px-4 py-2 rounded-lg text-sm font-bold transition-colors"
          >
            <i className="fas fa-sync mr-2"></i>Actualizar
          </button>
        </div>
        <div className="overflow-x-auto -mx-6">
          <table className="w-full text-left min-w-[900px]">
            <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
              <tr>
                <th className="px-6 py-4">Folio / Ticket</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Logística (Chofer)</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {tickets.map((ticket) => {
                const driverInfo = ticket.embarque && ticket.embarque.length > 0 
                  ? ticket.embarque[0].chofer 
                  : <span className="text-gray-300">--</span>;

                return (
                  <tr key={ticket.folio} className="hover:bg-blue-50/20 transition-colors group">
                    <td className="px-6 py-4">
                      <div className="font-black text-gray-900">{ticket.no_tiket}</div>
                      <div className="font-mono text-[10px] text-gray-400">{ticket.folio.substring(0,8)}...</div>
                    </td>
                    <td className="px-6 py-4 text-gray-600 font-medium text-xs">
                      {ticket.nombre_cliente.split('|')[0].substring(0,25)}
                    </td>
                    <td className="px-6 py-4 text-gray-600 font-bold text-xs uppercase">
                      {driverInfo}
                    </td>
                    <td className="px-6 py-4 text-gray-500 text-xs">${ticket.monto_de_compra}</td>
                    <td className="px-6 py-4">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${getStatusColor(ticket.estado)}`}>
                        {ticket.estado}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right flex justify-end gap-2">
                      <button 
                        onClick={() => setViewingTicket(ticket)}
                        className="text-gray-500 hover:text-gray-700 p-2 rounded-lg hover:bg-gray-100 transition-all shadow-sm border border-gray-100"
                        title="Ver Detalles Completos"
                      >
                        <i className="fas fa-eye"></i>
                      </button>
                      <button 
                        onClick={() => setEditingTicket({ ...ticket })}
                        className="text-blue-800 hover:text-blue-900 p-2 rounded-lg hover:bg-blue-100 transition-all shadow-sm border border-blue-100"
                        title="Editar Pedido"
                      >
                        <i className="fas fa-edit"></i>
                      </button>
                      <button 
                        onClick={() => deleteTicket(ticket.folio)}
                        className="text-red-500 hover:text-red-700 p-2 rounded-lg hover:bg-red-50 transition-all shadow-sm border border-red-100"
                        title="Eliminar Pedido"
                      >
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Stats Summary Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-gray-800">
          <i className="fas fa-chart-pie text-red-600"></i>
          Resumen Logístico
        </h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
              <XAxis type="number" hide />
              <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={100} />
              <Tooltip 
                cursor={{fill: 'transparent'}}
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} 
              />
              <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={40}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* View Details Modal */}
      {viewingTicket && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-slideUp max-h-[90vh] overflow-y-auto">
            <div className="bg-gray-800 text-white p-6 flex justify-between items-center sticky top-0 z-10">
              <div>
                <h4 className="text-xl font-black">Detalles del Pedido</h4>
                <p className="text-gray-300 text-xs font-mono">ID: {viewingTicket.folio}</p>
              </div>
              <button onClick={() => setViewingTicket(null)} className="text-gray-400 hover:text-white transition-colors">
                <i className="fas fa-times text-2xl"></i>
              </button>
            </div>

            <div className="p-6 space-y-6">
              {/* General Info */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                  <h5 className="font-bold text-blue-800 uppercase text-xs border-b border-blue-100 pb-2">Información del Cliente</h5>
                  <div>
                    <p className="text-xs text-gray-500 uppercase font-bold">Ticket No.</p>
                    <p className="text-xl font-black">{viewingTicket.no_tiket}</p>
                  </div>
                  <div>
                    <p className="text-xs text-gray-500 uppercase font-bold">Cliente</p>
                    <p className="font-medium">{viewingTicket.nombre_cliente.split('|')[0]}</p>
                  </div>
                  <div>
                    <p className="text-xs text-gray-500 uppercase font-bold">Dirección</p>
                    <p className="text-sm">{viewingTicket.nombre_cliente.split('|')[1] || 'No especificada'}</p>
                  </div>
                   <div>
                    <p className="text-xs text-gray-500 uppercase font-bold">Contacto</p>
                    <p className="font-bold"><i className="fas fa-phone mr-1"></i> {viewingTicket.telefono}</p>
                  </div>
                </div>

                <div className="space-y-4">
                  <h5 className="font-bold text-orange-600 uppercase text-xs border-b border-orange-100 pb-2">Datos de Logística (Embarque)</h5>
                  {viewingTicket.embarque && viewingTicket.embarque.length > 0 ? (
                    <>
                       <div>
                        <p className="text-xs text-gray-500 uppercase font-bold">Chofer Asignado</p>
                        <p className="text-lg font-bold text-gray-800">{viewingTicket.embarque[0].chofer}</p>
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <p className="text-xs text-gray-500 uppercase font-bold">Unidad</p>
                          <p className="font-medium uppercase">{viewingTicket.embarque[0].unidad}</p>
                        </div>
                        <div>
                          <p className="text-xs text-gray-500 uppercase font-bold">Placas</p>
                          <p className="font-medium uppercase">{viewingTicket.embarque[0].placas}</p>
                        </div>
                      </div>
                    </>
                  ) : (
                    <p className="text-sm text-gray-400 italic">No se ha generado embarque aún.</p>
                  )}

                  <div className="mt-4 pt-4 border-t border-dashed border-gray-200">
                     <p className="text-xs text-gray-500 uppercase font-bold">Estado Actual</p>
                     <span className={`inline-block mt-1 px-3 py-1 rounded-full text-xs font-black uppercase border ${getStatusColor(viewingTicket.estado)}`}>
                        {viewingTicket.estado}
                      </span>
                  </div>
                </div>
              </div>

              {/* Evidence Section */}
              <div className="border-t-4 border-gray-100 pt-6">
                <h5 className="font-bold text-red-600 uppercase text-xs mb-4 flex items-center gap-2">
                  <i className="fas fa-camera"></i> Evidencia de Entrega / Incidencia
                </h5>

                {viewingTicket.evidencias_entrega && viewingTicket.evidencias_entrega.length > 0 ? (
                  <div className="grid grid-cols-1 gap-4">
                    {viewingTicket.evidencias_entrega.map((evidence, idx) => (
                      <div key={idx} className="bg-gray-50 p-4 rounded-xl border border-gray-200">
                        <p className="text-xs text-gray-400 mb-2 font-mono text-right">{new Date(evidence.created_at).toLocaleString()}</p>
                        <div className="rounded-lg overflow-hidden shadow-md">
                          <img 
                            src={evidence.evidencia_fotografica} 
                            alt={`Evidencia ${idx + 1}`} 
                            className="w-full h-auto object-cover max-h-[300px]"
