export default AdminView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Interface used only for the report generation to handle joined data
interface ReportPedido extends Pedido {
  embarque?: { unidad: string; placas: string; chofer: string }[];
  evidencias_entrega?: { evidencia_fotografica: string; created_at: string }[];
}

const AdminView: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [tickets, setTickets] = useState<Pedido[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [editingTicket, setEditingTicket] = useState<Pedido | null>(null);

  // States for Report Generation
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetchTickets();
      // Set default report dates (current month)
      const date = new Date();
      const firstDay = new Date(date.getFullYear(), date.getMonth(), 1).toISOString().split('T')[0];
      const currentDay = date.toISOString().split('T')[0];
      setStartDate(firstDay);
      setEndDate(currentDay);
    }
  }, [isLoggedIn]);

  const fetchTickets = async () => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('pedido')
      .select('*')
      .order('created_at', { ascending: false });

    if (data) setTickets(data as Pedido[]);
    setIsLoading(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'FerreNico25') {
      setIsLoggedIn(true);
    } else {
      alert("Clave de administrador incorrecta");
    }
  };

  const updateTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTicket) return;

    const { error } = await supabase
      .from('pedido')
      .update({ 
        estado: editingTicket.estado,
        no_tiket: editingTicket.no_tiket,
        monto_de_compra: editingTicket.monto_de_compra
      })
      .eq('folio', editingTicket.folio);

    if (!error) {
      alert("Datos actualizados correctamente.");
      setEditingTicket(null);
      fetchTickets();
    } else {
      alert("Error al actualizar: " + error.message);
    }
  };

  const deleteTicket = async (folio: string) => {
    if (window.confirm("¿Está seguro de que desea ELIMINAR este pedido permanentemente? Esta acción no se puede deshacer.")) {
      try {
        const { error } = await supabase
          .from('pedido')
          .delete()
          .eq('folio', folio);

        if (error) throw error;

        alert("Pedido eliminado correctamente.");
        fetchTickets();
      } catch (error: any) {
        console.error("Error al eliminar:", error);
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  const generateReport = async () => {
    if (!startDate || !endDate) {
      alert("Por favor seleccione ambas fechas para el reporte.");
      return;
    }

    setIsGeneratingReport(true);
    try {
      // Fetch specifically for report including joined tables (Shipment and Evidence)
      // This does not affect the main view state
      const { data, error } = await supabase
        .from('pedido')
        .select(`
          *,
          embarque ( unidad, placas, chofer ),
          evidencias_entrega ( created_at )
        `)
        .gte('created_at', `${startDate}T00:00:00`)
        .lte('created_at', `${endDate}T23:59:59`)
        .order('created_at', { ascending: true });

      if (error) throw error;

      if (!data || data.length === 0) {
        alert("No se encontraron registros en ese rango de fechas.");
        setIsGeneratingReport(false);
        return;
      }

      // Prepare CSV Data
      const headers = [
        "Fecha", 
        "Ticket", 
        "Cliente", 
        "Direccion", 
        "Telefono", 
        "Unidades", 
        "Estado", 
        "Monto Compra", 
        "Costo Envio", 
        "Total", 
        "Chofer", 
        "Unidad", 
        "Placas",
        "Tiene Evidencia"
      ];

      const csvRows = (data as ReportPedido[]).map(order => {
        const date = new Date(order.created_at || '').toLocaleDateString();
        const cleanName = order.nombre_cliente.split('|')[0]?.trim() || '';
        const cleanAddress = (order.nombre_cliente.split('|')[1]?.trim() || order.nombre_cliente).replace(/,/g, ' '); 
        const total = (order.monto_de_compra + order.costo_de_envio).toFixed(2);

        // Extract logistics info (assuming 1 shipment per order usually)
        const shipment = order.embarque && order.embarque.length > 0 ? order.embarque[0] : { chofer: '', unidad: '', placas: '' };
        const hasEvidence = order.evidencias_entrega && order.evidencias_entrega.length > 0 ? "SI" : "NO";

        return [
          date,
          order.no_tiket,
          cleanName,
          cleanAddress,
          order.telefono,
          order.unidades,
          order.estado,
          order.monto_de_compra,
          order.costo_de_envio,
          total,
          shipment.chofer,
          shipment.unidad,
          shipment.placas,
          hasEvidence
        ].join(',');
      });

      const csvContent = "data:text/csv;charset=utf-8," 
        + headers.join(',') + "\n" 
        + csvRows.join('\n');

      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `Reporte_FerreNico_${startDate}_al_${endDate}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

    } catch (error: any) {
      console.error("Error generating report:", error);
      alert("Error generando el reporte: " + error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case TicketStatus.DELIVERED: return 'bg-green-100 text-green-700 border-green-200';
      case TicketStatus.IN_TRANSIT: return 'bg-blue-100 text-blue-700 border-blue-200';
      case TicketStatus.PENDING: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case TicketStatus.NOT_FOUND: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const chartData = [
    { name: 'Entregados', value: tickets.filter(t => t.estado === TicketStatus.DELIVERED).length },
    { name: 'En Tránsito', value: tickets.filter(t => t.estado === TicketStatus.IN_TRANSIT).length },
    { name: 'Pendientes', value: tickets.filter(t => t.estado === TicketStatus.PENDING).length },
    { name: 'Incidencias', value: tickets.filter(t => t.estado === TicketStatus.NOT_FOUND).length },
  ];

  const COLORS = ['#16a34a', '#1e40af', '#ca8a04', '#dc2626'];

  if (!isLoggedIn) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-fadeIn">
        <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-2xl border-t-4 border-blue-800">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-blue-800 text-white rounded-2xl mb-4">
              <i className="fas fa-lock text-2xl"></i>
            </div>
            <h2 className="text-2xl font-black text-gray-800">Acceso Restringido</h2>
            <p className="text-gray-500">Ingrese su clave de administrador</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-blue-800 focus:ring-0 text-center text-2xl tracking-widest outline-none transition-all"
              autoFocus
            />
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg transform active:scale-95 border-b-4 border-blue-950"
            >
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      {isLoading && <p className="text-center text-gray-500">Cargando datos de Supabase...</p>}

      {/* Stats Cards */}
