            <div className="border-t border-b border-black py-2 mb-4">
              <p className="font-bold mb-1 text-[10px] uppercase bg-black text-white inline-block px-1">DATOS DE ENTREGA:</p>
              <p className="uppercase text-[11px] leading-tight font-bold mt-1">{printOrder.nombre_cliente}</p>
              <p className="mt-1 text-[11px] font-bold"><i className="fas fa-phone mr-1"></i> Tel: {printOrder.telefono}</p>
            </div>

            <div className="space-y-1 text-right mb-4 text-[10px] font-mono">
                <div className="flex justify-between">
                <span>UNIDADES:</span>
                <span>{printOrder.unidades} pzs</span>
              </div>
              <div className="flex justify-between">
                <span>SUBTOTAL:</span>
                <span>${printOrder.monto_de_compra.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>ENVIO:</span>
                <span>${printOrder.costo_de_envio.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-sm font-black border-t-2 border-black pt-1 mt-1">
                <span>TOTAL A COBRAR:</span>
                <span>${(printOrder.monto_de_compra + printOrder.costo_de_envio).toFixed(2)}</span>
              </div>
            </div>

            <div className="mt-8 mb-6 text-center">
              <div className="h-16 mb-2 border-b border-black"></div>
              <p className="text-[9px] font-bold uppercase">Firma de Recibido / Sello</p>
            </div>

            <div className="text-center text-[9px] mt-4 border-t border-black pt-2">
              <p className="font-bold">*** FERRE DON NICO ***</p>
              <p>Gracias por su preferencia</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

