import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { TicketStatus, Pedido } from '../types';

const DeliveryView: React.FC = () => {
  const [folio, setFolio] = useState('');
  const [showFailureForm, setShowFailureForm] = useState(false);
  const [observation, setObservation] = useState('');
  const [hasPhoto, setHasPhoto] = useState(false);
  const [photoBase64, setPhotoBase64] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // New state for dropdown
  const [inTransitOrders, setInTransitOrders] = useState<Pedido[]>([]);
  const [loadingList, setLoadingList] = useState(false);

  // Fetch orders on mount
  useEffect(() => {
    fetchInTransitOrders();
  }, []);

  const fetchInTransitOrders = async () => {
    setLoadingList(true);
    try {
      const { data, error } = await supabase
        .from('pedido')
        .select('*')
        .eq('estado', TicketStatus.IN_TRANSIT);

      if (error) throw error;
      if (data) setInTransitOrders(data);
    } catch (error) {
      console.error("Error fetching in-transit orders:", error);
    } finally {
      setLoadingList(false);
    }
  };

  const resetForm = () => {
    setFolio('');
    setShowFailureForm(false);
    setObservation('');
    setHasPhoto(false);
    setPhotoBase64('');
    // Refresh list to remove the processed order
    fetchInTransitOrders();
  };

  const handleDelivered = async () => {
    if (!folio.trim()) {
      alert("Por favor seleccione un pedido.");
      return;
    }

    setIsSubmitting(true);

    try {
      const { error } = await supabase
        .from('pedido')
        .update({ estado: TicketStatus.DELIVERED })
        .eq('folio', folio.trim());

      if (error) throw error;

      alert(`✅ Pedido marcado como ENTREGADO exitosamente.`);
      resetForm();
    } catch (error: any) {
      console.error('Error updating delivery:', error);
      alert('Error al actualizar: ' + error.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleNotDeliveredInit = () => {
    if (!folio.trim()) {
      alert("Por favor seleccione un pedido.");
      return;
    }
    setShowFailureForm(true);
  };

  const handleSubmitFailure = async () => {
    if (!observation.trim()) {
      alert("Por favor ingrese una observación.");
      return;
    }
    if (!hasPhoto || !photoBase64) {
      alert("Es necesario adjuntar evidencia fotográfica.");
      return;
    }

    setIsSubmitting(true);

    try {
      // 1. Update Pedido Status
      const { error: updateError } = await supabase
        .from('pedido')
        .update({ estado: TicketStatus.NOT_FOUND }) 
        .eq('folio', folio.trim());

      if (updateError) throw updateError;

      // 2. Insert Evidence
      const { error: insertError } = await supabase
        .from('evidencias_entrega')
        .insert([{
           folio: folio, 
           evidencia_fotografica: photoBase64
        }]);

      if (insertError) throw insertError;

      alert(`⚠️ Incidencia reportada.\nEstado: NO ENTREGADO / NO ENCONTRADO`);
      resetForm();

    } catch (error: any) {
      console.error('Error reporting failure:', error);
      alert('Error al reportar incidencia: ' + error.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      setHasPhoto(true);

      const reader = new FileReader();
      reader.onloadend = () => {
        if (typeof reader.result === 'string') {
          setPhotoBase64(reader.result);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const selectedOrderInfo = inTransitOrders.find(o => o.folio === folio);

  return (
    <div className="animate-fadeIn">
      <div className="bg-white p-6 rounded-2xl shadow-xl border-t-4 border-red-600 max-w-lg mx-auto">
        {/* Header */}
        <div className="flex items-center gap-4 mb-8 border-b border-gray-100 pb-6">
          <div className="p-4 bg-red-100 text-red-600 rounded-2xl">
            <i className="fas fa-box-open text-3xl"></i>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-800">Confirmar Entrega</h2>
            <p className="text-sm text-gray-500">Pedidos En Tránsito</p>
          </div>
        </div>

        {/* Folio Selection Section */}
        <div className="mb-6">
          <label className="block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest pl-1">
            Seleccionar Pedido {loadingList && <i className="fas fa-spinner fa-spin ml-2"></i>}
          </label>
          <div className="relative">
            <i className="fas fa-truck-loading absolute left-5 top-1/2 transform -translate-y-1/2 text-gray-400 text-xl"></i>
            <select
              value={folio}
              onChange={(e) => setFolio(e.target.value)}
              disabled={showFailureForm || isSubmitting}
              className="w-full pl-14 pr-4 py-5 text-sm font-bold border-2 border-gray-100 rounded-2xl focus:border-red-600 focus:ring-0 outline-none transition-all bg-gray-50 text-gray-900 appearance-none truncate"
            >
              <option value="">-- Seleccionar de la lista --</option>
              {inTransitOrders.map((order) => (
                <option key={order.folio} value={order.folio}>
                  {order.no_tiket} - {order.nombre_cliente.split('|')[0].trim()}
                </option>
              ))}
            </select>
            <div className="absolute right-5 top-1/2 transform -translate-y-1/2 pointer-events-none">
              <i className="fas fa-chevron-down text-gray-400"></i>
            </div>
          </div>

          {/* Display Details if selected */}
          {selectedOrderInfo && (
            <div className="mt-4 p-4 bg-gray-50 rounded-xl border border-gray-100 animate-fadeIn">
              <p className="text-xs text-gray-500 font-bold uppercase mb-1">Dirección de Entrega:</p>
              <p className="text-sm font-medium text-gray-800">
                {selectedOrderInfo.nombre_cliente.includes('|') 
                  ? selectedOrderInfo.nombre_cliente.split('|')[1] 
                  : 'Dirección no especificada en cliente'}
              </p>
              <div className="flex gap-4 mt-3">
                 <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded font-bold">
                   <i className="fas fa-phone mr-1"></i> {selectedOrderInfo.telefono}
                 </span>
                 <span className="text-xs bg-gray-200 text-gray-700 px-2 py-1 rounded font-bold">
                   <i className="fas fa-box mr-1"></i> {selectedOrderInfo.unidades} pzs
                 </span>
              </div>
            </div>
          )}
        </div>

        {/* Action Buttons */}
        {!showFailureForm ? (
          <div className="grid grid-cols-1 gap-4 animate-fadeIn">
            <button 
              onClick={handleDelivered}
              disabled={isSubmitting || !folio}
              className="group relative overflow-hidden w-full bg-green-500 hover:bg-green-600 text-white p-6 rounded-2xl transition-all shadow-lg shadow-green-200 active:scale-[0.98] disabled:opacity-50 disabled:active:scale-100 disabled:cursor-not-allowed border-b-4 border-green-700"
            >
              <div className="relative z-10 flex items-center justify-between">
                <span className="text-xl font-black tracking-tight">ENTREGADO</span>
                <i className="fas fa-check-circle text-3xl group-hover:scale-110 transition-transform"></i>
              </div>
              <div className="absolute inset-0 bg-green-600 transform scale-x-0 group-hover:scale-x-100 transition-transform origin-left duration-300"></div>
            </button>

            <button 
              onClick={handleNotDeliveredInit}
              disabled={isSubmitting || !folio}
              className="group w-full bg-red-50 hover:bg-red-100 text-red-600 border-2 border-red-100 p-6 rounded-2xl transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <div className="flex items-center justify-between">
                <span className="text-lg font-bold">NO ENTREGADO</span>
                <i className="fas fa-times-circle text-2xl"></i>
              </div>
            </button>
          </div>
        ) : (
          /* Failure Form */
          <div className="space-y-5 animate-slideUp bg-red-50 p-6 rounded-3xl border border-red-100">
            <div className="flex items-center gap-2 text-red-700 mb-2">
              <i className="fas fa-exclamation-triangle"></i>
              <h3 className="font-bold">Reporte de Incidencia</h3>
            </div>

            {/* Photo Evidence */}
            <div className="relative group">
              <input 
                type="file" 
                accept="image/*" 
                capture="environment" 
                onChange={handlePhotoChange}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
              />
              <div className={`w-full py-8 flex flex-col items-center justify-center border-2 border-dashed rounded-2xl transition-all ${hasPhoto ? 'border-green-500 bg-green-50' : 'border-red-200 bg-white group-hover:bg-red-50'}`}>
                <div className={`p-3 rounded-full mb-3 ${hasPhoto ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-400'}`}>
                  <i className={`fas ${hasPhoto ? 'fa-check text-xl' : 'fa-camera text-xl'}`}></i>
                </div>
                <span className={`text-sm font-bold ${hasPhoto ? 'text-green-700' : 'text-gray-500'}`}>
                  {hasPhoto ? 'Evidencia Adjuntada' : 'Tomar Foto de Domicilio'}
                </span>
              </div>
            </div>

            {/* Observation Text */}
            <div>
              <label className="block text-xs font-bold text-red-700 mb-2 uppercase">Motivo de no entrega</label>
              <textarea 
                value={observation}
                onChange={(e) => setObservation(e.target.value)}
                placeholder="Describa la razón (ej. Domicilio incorrecto, Cliente ausente)..."
                className="w-full p-4 border border-red-200 rounded-xl h-32 focus:ring-2 focus:ring-red-500 outline-none resize-none bg-white text-sm text-gray-900"
              />
            </div>

            {/* Form Actions */}
            <div className="flex gap-3 pt-2">
              <button 
                onClick={() => setShowFailureForm(false)}
                disabled={isSubmitting}
                className="flex-1 bg-white text-gray-600 font-bold py-4 rounded-xl border border-gray-200 hover:bg-gray-50 transition-all text-sm"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSubmitFailure}
                disabled={isSubmitting}
                className="flex-1 bg-red-600 text-white font-bold py-4 rounded-xl hover:bg-red-700 shadow-lg shadow-red-200 transition-all text-sm flex items-center justify-center gap-2"
              >
                {isSubmitting ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
                Enviar Reporte
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const AdminView: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [tickets, setTickets] = useState<Pedido[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [editingTicket, setEditingTicket] = useState<Pedido | null>(null);

  // States for Report Generation
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetchTickets();
      // Set default report dates (current month)
      const date = new Date();
      const firstDay = new Date(date.getFullYear(), date.getMonth(), 1).toISOString().split('T')[0];
      const currentDay = date.toISOString().split('T')[0];
      setStartDate(firstDay);
      setEndDate(currentDay);
    }
  }, [isLoggedIn]);

  const fetchTickets = async () => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('pedido')
      .select('*')
      .order('created_at', { ascending: false });

    if (data) setTickets(data as Pedido[]);
    setIsLoading(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'FerreNico25') {
      setIsLoggedIn(true);
    } else {
      alert("Clave de administrador incorrecta");
    }
  };

  const updateTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTicket) return;

    const { error } = await supabase
      .from('pedido')
      .update({ 
        estado: editingTicket.estado,
        no_tiket: editingTicket.no_tiket,
        monto_de_compra: editingTicket.monto_de_compra
      })
      .eq('folio', editingTicket.folio);

    if (!error) {
      alert("Datos actualizados correctamente.");
      setEditingTicket(null);
      fetchTickets();
    } else {
      alert("Error al actualizar: " + error.message);
    }
  };

  const deleteTicket = async (folio: string) => {
    if (window.confirm("¿Está seguro de que desea ELIMINAR este pedido permanentemente? Esta acción no se puede deshacer.")) {
      try {
        // 1. Eliminar evidencias relacionadas primero (para evitar error de FK)
        const { error: evidenceError } = await supabase
          .from('evidencias_entrega')
          .delete()
          .eq('folio', folio);

        if (evidenceError) console.warn("Nota: No se pudieron borrar evidencias (o no existían):", evidenceError.message);

        // 2. Eliminar embarque relacionado
        const { error: shipmentError } = await supabase
          .from('embarque')
          .delete()
          .eq('folio', folio);

        if (shipmentError) console.warn("Nota: No se pudo borrar embarque (o no existía):", shipmentError.message);

        // 3. Eliminar el pedido principal
        const { error } = await supabase
          .from('pedido')
          .delete()
          .eq('folio', folio);

        if (error) throw error;

        alert("Pedido eliminado correctamente.");
        fetchTickets();
      } catch (error: any) {
        console.error("Error al eliminar:", error);
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  const generateReport = async () => {
    if (!startDate || !endDate) {
      alert("Por favor seleccione ambas fechas para el reporte.");
      return;
    }

    setIsGeneratingReport(true);
    try {
      // 1. Consulta a Supabase con Joins
      // Seleccionamos solo los campos necesarios y la relación con embarque
      const { data, error } = await supabase
        .from('pedido')
        .select(`
          created_at,
          no_tiket,
          nombre_cliente,
          telefono,
          unidades,
          estado,
          monto_de_compra,
          embarque ( unidad )
        `)
        .gte('created_at', `${startDate}T00:00:00`)
        .lte('created_at', `${endDate}T23:59:59`)
        .order('created_at', { ascending: true });

      if (error) throw error;

      if (!data || data.length === 0) {
        alert("No se encontraron registros en ese rango de fechas.");
        setIsGeneratingReport(false);
        return;
      }

      // 2. Definir encabezados CSV (Solo los solicitados)
      const headers = [
        "Fecha", 
        "Ticket", 
        "Cliente", 
        "Direccion", 
        "Unidades", 
        "Estado", 
        "Monto Compra", 
        "Unidad"
      ];

      // OPTIMIZACIÓN: Usar punto y coma (;) como separador para Excel en español
      const SEPARATOR = ';';

      // Función auxiliar para escapar caracteres especiales en CSV
      const escapeCsv = (val: any) => {
        if (val === null || val === undefined) return '';
        const str = String(val);
        // Si contiene el separador, comillas o saltos de línea, lo envolvemos en comillas
        if (str.includes(SEPARATOR) || str.includes('"') || str.includes('\n')) {
          return `"${str.replace(/"/g, '""')}"`;
        }
        return str;
      };

      // 3. Procesar filas
      const csvRows = data.map((order: any) => {
        const date = new Date(order.created_at || '').toLocaleDateString();
        const fullClientName = order.nombre_cliente || '';
        const parts = fullClientName.split('|');
        const cleanName = parts[0]?.trim() || fullClientName;
        // Si no hay pipe |, asumimos que todo es nombre y la dirección está vacía o implícita
        const cleanAddress = parts.length > 1 ? parts[1]?.trim() : ''; 

        // Manejo seguro de datos anidados (pueden ser array o null)
        const embarqueData = Array.isArray(order.embarque) && order.embarque.length > 0 
          ? order.embarque[0] 
          : (order.embarque || {});

        const unit = embarqueData.unidad || 'Sin Asignar';

        // Mapear los valores a las columnas correspondientes
        return [
          date,
          order.no_tiket,
          cleanName,
          cleanAddress,
          order.unidades,
          order.estado,
          order.monto_de_compra,
          unit
        ].map(escapeCsv).join(SEPARATOR);
      });

      // 4. Generar Blob y descargar
      // Agregamos BOM (\uFEFF) para que Excel reconozca UTF-8 correctamente
      const csvContent = '\uFEFF' + headers.join(SEPARATOR) + '\n' + csvRows.join('\n');
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });

      // Crear URL temporal
      const url = URL.createObjectURL(blob);

      const link = document.createElement("a");
      link.href = url;
      link.setAttribute("download", `Reporte_FerreNico_${startDate}_al_${endDate}.csv`);
      document.body.appendChild(link);
      link.click();

      // Limpieza de recursos
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

    } catch (error: any) {
      console.error("Error generating report:", error);
      alert("Error generando el reporte: " + error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case TicketStatus.DELIVERED: return 'bg-green-100 text-green-700 border-green-200';
      case TicketStatus.IN_TRANSIT: return 'bg-blue-100 text-blue-700 border-blue-200';
      case TicketStatus.PENDING: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case TicketStatus.NOT_FOUND: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const chartData = [
    { name: 'Entregados', value: tickets.filter(t => t.estado === TicketStatus.DELIVERED).length },
    { name: 'En Tránsito', value: tickets.filter(t => t.estado === TicketStatus.IN_TRANSIT).length },
    { name: 'Pendientes', value: tickets.filter(t => t.estado === TicketStatus.PENDING).length },
    { name: 'Incidencias', value: tickets.filter(t => t.estado === TicketStatus.NOT_FOUND).length },
  ];

  const COLORS = ['#16a34a', '#1e40af', '#ca8a04', '#dc2626'];

  if (!isLoggedIn) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-fadeIn">
        <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-2xl border-t-4 border-blue-800">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-blue-800 text-white rounded-2xl mb-4">
              <i className="fas fa-lock text-2xl"></i>
            </div>
            <h2 className="text-2xl font-black text-gray-800">Acceso Restringido</h2>
            <p className="text-gray-500">Ingrese su clave de administrador</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-blue-800 focus:ring-0 text-center text-2xl tracking-widest outline-none transition-all bg-gray-50 text-gray-900"
              autoFocus
            />
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg transform active:scale-95 border-b-4 border-blue-950"
            >
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      {isLoading && <p className="text-center text-gray-500">Cargando datos de Supabase...</p>}

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {chartData.map((item, i) => (
          <div key={item.name} className={`bg-white p-4 rounded-2xl shadow-sm border-l-4`} style={{ borderLeftColor: COLORS[i] }}>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{item.name}</p>
            <p className="text-2xl font-black">{item.value}</p>
          </div>
        ))}
      </div>

      {/* Report Generator Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800 mb-4">
          <i className="fas fa-file-excel text-green-600"></i>
          Generar Reporte Excel
        </h3>
        <div className="flex flex-col md:flex-row items-end gap-4">
          <div className="w-full md:w-auto">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Inicio</label>
            <input 
              type="date" 
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium bg-gray-50 text-gray-900"
            />
          </div>
          <div className="w-full md:w-auto">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Fin</label>
            <input 
              type="date" 
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium bg-gray-50 text-gray-900"
            />
          </div>
          <button 
            onClick={generateReport}
            disabled={isGeneratingReport}
            className="w-full md:w-auto px-6 py-2.5 bg-green-600 hover:bg-green-700 text-white font-bold rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
          >
            {isGeneratingReport ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-download"></i>}
            Descargar Reporte Completo
          </button>
        </div>
        <p className="text-[10px] text-gray-400 mt-2 italic">
          * El reporte optimizado incluye: Fecha, Ticket, Cliente, Dirección, Unidades, Estado, Monto y Unidad.
        </p>
      </div>

      {/* Table Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
            <i className="fas fa-list-check text-blue-800"></i>
            Bitácora de Pedidos
          </h3>
          <button 
            onClick={fetchTickets}
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 px-4 py-2 rounded-lg text-sm font-bold transition-colors"
          >
            <i className="fas fa-sync mr-2"></i>Actualizar
          </button>
        </div>
        <div className="overflow-x-auto -mx-6">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
              <tr>
                <th className="px-6 py-4">Folio / Ticket</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {tickets.map((ticket) => (
                <tr key={ticket.folio} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-black text-gray-900">{ticket.no_tiket}</div>
                    <div className="font-mono text-[10px] text-gray-400">{ticket.folio.substring(0,8)}...</div>
                  </td>
                  <td className="px-6 py-4 text-gray-600 font-medium text-xs">
                    {ticket.nombre_cliente.split('|')[0].substring(0,30)}
                  </td>
                  <td className="px-6 py-4 text-gray-500 text-xs">${ticket.monto_de_compra}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${getStatusColor(ticket.estado)}`}>
                      {ticket.estado}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right flex justify-end gap-2">
                    <button 
                      onClick={() => setEditingTicket({ ...ticket })}
                      className="text-blue-800 hover:text-blue-900 p-2 rounded-lg hover:bg-blue-100 transition-all shadow-sm border border-blue-100"
                      title="Editar Pedido"
                    >
                      <i className="fas fa-edit"></i>
                    </button>
                    <button 
                      onClick={() => deleteTicket(ticket.folio)}
                      className="text-red-500 hover:text-red-700 p-2 rounded-lg hover:bg-red-50 transition-all shadow-sm border border-red-100"
                      title="Eliminar Pedido"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Stats Summary Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-gray-800">
          <i className="fas fa-chart-pie text-red-600"></i>
          Resumen Logístico
        </h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
              <XAxis type="number" hide />
              <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={100} />
              <Tooltip 
                cursor={{fill: 'transparent'}}
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} 
              />
              <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={40}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Edit Modal */}
      {editingTicket && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
