    }
  }, [isLoggedIn]);

  const fetchTickets = async () => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('pedido')
      .select('*')
      .order('created_at', { ascending: false });

    if (data) setTickets(data as Pedido[]);
    setIsLoading(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'FerreNico25') {
      setIsLoggedIn(true);
    } else {
      alert("Clave de administrador incorrecta");
    }
  };

  const updateTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTicket) return;

    const { error } = await supabase
      .from('pedido')
      .update({ 
        estado: editingTicket.estado,
        no_tiket: editingTicket.no_tiket,
        monto_de_compra: editingTicket.monto_de_compra
      })
      .eq('folio', editingTicket.folio);

    if (!error) {
      alert("Datos actualizados correctamente.");
      setEditingTicket(null);
      fetchTickets();
    } else {
      alert("Error al actualizar: " + error.message);
    }
  };

  const deleteTicket = async (folio: string) => {
    if (window.confirm("¿Está seguro de que desea ELIMINAR este pedido permanentemente? Esta acción no se puede deshacer.")) {
      try {
        // 1. Eliminar evidencias relacionadas primero (para evitar error de FK)
        const { error: evidenceError } = await supabase
          .from('evidencias_entrega')
          .delete()
          .eq('folio', folio);

        if (evidenceError) console.warn("Nota: No se pudieron borrar evidencias (o no existían):", evidenceError.message);

        // 2. Eliminar embarque relacionado
        const { error: shipmentError } = await supabase
          .from('embarque')
          .delete()
          .eq('folio', folio);

        if (shipmentError) console.warn("Nota: No se pudo borrar embarque (o no existía):", shipmentError.message);

        // 3. Eliminar el pedido principal
        const { error } = await supabase
          .from('pedido')
          .delete()
          .eq('folio', folio);

        if (error) throw error;

        alert("Pedido eliminado correctamente.");
        fetchTickets();
      } catch (error: any) {
        console.error("Error al eliminar:", error);
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  const generateReport = async () => {
    if (!startDate || !endDate) {
      alert("Por favor seleccione ambas fechas para el reporte.");
      return;
    }

    setIsGeneratingReport(true);

    // OPTIMIZACIÓN: Usar punto y coma (;) como separador para Excel en español
    const SEPARATOR = ';';

    // Función auxiliar para escapar caracteres especiales en CSV
    const escapeCsv = (val: any) => {
      if (val === null || val === undefined) return '';
      const str = String(val);
      // Si contiene el separador, comillas o saltos de línea, lo envolvemos en comillas
      if (str.includes(SEPARATOR) || str.includes('"') || str.includes('\n')) {
        return `"${str.replace(/"/g, '""')}"`;
      }
      return str;
    };

    try {
      let data: any[] = [];
      let headers: string[] = [];
      let csvRows: string[] = [];
      let fileNamePrefix = '';

      if (reportType === 'orders') {
        // --- REPORTE DE PEDIDOS ---
        fileNamePrefix = 'Reporte_Pedidos';
        const { data: res, error } = await supabase
          .from('pedido')
          .select(`created_at, no_tiket, nombre_cliente, telefono, unidades, estado, monto_de_compra`)
          .gte('created_at', `${startDate}T00:00:00`)
          .lte('created_at', `${endDate}T23:59:59`)
          .order('created_at', { ascending: true });

        if (error) throw error;
        data = res || [];

        headers = ["Fecha", "Ticket", "Cliente", "Direccion", "Unidades", "Estado", "Monto Compra"];

        csvRows = data.map((order: any) => {
          const date = new Date(order.created_at || '').toLocaleDateString();
          const fullClientName = order.nombre_cliente || '';
          const parts = fullClientName.split('|');
          const cleanName = parts[0]?.trim() || fullClientName;
          const cleanAddress = parts.length > 1 ? parts[1]?.trim() : ''; 

          return [
            date,
            order.no_tiket,
            cleanName,
            cleanAddress,
            order.unidades,
            order.estado,
            order.monto_de_compra
          ].map(escapeCsv).join(SEPARATOR);
        });

      } else if (reportType === 'shipments') {
        // --- REPORTE DE EMBARQUES ---
        fileNamePrefix = 'Reporte_Embarques';
        // Join con pedido para obtener la fecha y el ticket
        const { data: res, error } = await supabase
          .from('embarque')
          .select(`
            folio,
            unidad,
            placas,
            chofer,
            pedido!inner ( created_at, no_tiket )
          `)
          .gte('pedido.created_at', `${startDate}T00:00:00`)
          .lte('pedido.created_at', `${endDate}T23:59:59`);

        if (error) throw error;
        data = res || [];

        headers = ["Fecha", "Folio Int.", "No. Ticket", "Unidad", "Placas", "Chofer"];

        csvRows = data.map((item: any) => {
          const date = new Date(item.pedido?.created_at || '').toLocaleDateString();
          return [
            date,
            item.folio,
            item.pedido?.no_tiket,
            item.unidad,
            item.placas,
            item.chofer
          ].map(escapeCsv).join(SEPARATOR);
        });

      } else if (reportType === 'evidence') {
        // --- REPORTE DE EVIDENCIAS ---
        fileNamePrefix = 'Reporte_Evidencias_Entrega';
        // Join con pedido para obtener la fecha y el ticket
        const { data: res, error } = await supabase
          .from('evidencias_entrega')
          .select(`
            folio,
            evidencia_fotografica,
            pedido!inner ( created_at, no_tiket )
          `)
          .gte('pedido.created_at', `${startDate}T00:00:00`)
          .lte('pedido.created_at', `${endDate}T23:59:59`);

        if (error) throw error;
        data = res || [];

        headers = ["Fecha", "Folio Int.", "No. Ticket", "Tiene Foto?"];

        csvRows = data.map((item: any) => {
          const date = new Date(item.pedido?.created_at || '').toLocaleDateString();
          // No descargamos el base64 completo para no romper Excel, solo indicamos si existe
          const hasPhoto = item.evidencia_fotografica && item.evidencia_fotografica.length > 50 ? 'SI' : 'NO';

          return [
            date,
            item.folio,
            item.pedido?.no_tiket,
            hasPhoto
          ].map(escapeCsv).join(SEPARATOR);
        });
      }

      if (!data || data.length === 0) {
        alert("No se encontraron registros en ese rango de fechas para el reporte seleccionado.");
        setIsGeneratingReport(false);
        return;
      }

      // 4. Generar Blob y descargar
      // Agregamos BOM (\uFEFF) para que Excel reconozca UTF-8 correctamente
      const csvContent = '\uFEFF' + headers.join(SEPARATOR) + '\n' + csvRows.join('\n');
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });

      // Crear URL temporal
      const url = URL.createObjectURL(blob);

      const link = document.createElement("a");
      link.href = url;
      link.setAttribute("download", `${fileNamePrefix}_${startDate}_al_${endDate}.csv`);
      document.body.appendChild(link);
      link.click();

      // Limpieza de recursos
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

    } catch (error: any) {
      console.error("Error generating report:", error);
      alert("Error generando el reporte: " + error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case TicketStatus.DELIVERED: return 'bg-green-100 text-green-700 border-green-200';
      case TicketStatus.IN_TRANSIT: return 'bg-blue-100 text-blue-700 border-blue-200';
      case TicketStatus.PENDING: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case TicketStatus.NOT_FOUND: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const chartData = [
    { name: 'Entregados', value: tickets.filter(t => t.estado === TicketStatus.DELIVERED).length },
    { name: 'En Tránsito', value: tickets.filter(t => t.estado === TicketStatus.IN_TRANSIT).length },
    { name: 'Pendientes', value: tickets.filter(t => t.estado === TicketStatus.PENDING).length },
    { name: 'Incidencias', value: tickets.filter(t => t.estado === TicketStatus.NOT_FOUND).length },
  ];

  const COLORS = ['#16a34a', '#1e40af', '#ca8a04', '#dc2626'];

  if (!isLoggedIn) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-fadeIn">
        <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-2xl border-t-4 border-blue-800">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-blue-800 text-white rounded-2xl mb-4">
              <i className="fas fa-lock text-2xl"></i>
            </div>
            <h2 className="text-2xl font-black text-gray-800">Acceso Restringido</h2>
            <p className="text-gray-500">Ingrese su clave de administrador</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-blue-800 focus:ring-0 text-center text-2xl tracking-widest outline-none transition-all bg-gray-50 text-gray-900"
              autoFocus
            />
            <button 
              type="submit"
              className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg transform active:scale-95 border-b-4 border-blue-950"
            >
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      {isLoading && <p className="text-center text-gray-500">Cargando datos de Supabase...</p>}

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {chartData.map((item, i) => (
          <div key={item.name} className={`bg-white p-4 rounded-2xl shadow-sm border-l-4`} style={{ borderLeftColor: COLORS[i] }}>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{item.name}</p>
            <p className="text-2xl font-black">{item.value}</p>
          </div>
        ))}
      </div>

      {/* Report Generator Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800 mb-4">
          <i className="fas fa-file-excel text-green-600"></i>
          Generar Reporte Excel
        </h3>

        <div className="flex flex-col gap-4">
          {/* Fila de controles */}
          <div className="flex flex-col md:flex-row items-end gap-4">

            {/* Tipo de Reporte */}
            <div className="w-full md:w-auto flex-1">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Tipo de Reporte</label>
              <div className="relative">
                <select 
                  value={reportType}
                  onChange={(e) => setReportType(e.target.value as any)}
                  className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium bg-gray-50 text-gray-900 appearance-none"
                >
                  <option value="orders">📋 Tabla Pedidos (General)</option>
                  <option value="shipments">🚚 Tabla Embarques (Salidas)</option>
                  <option value="evidence">📸 Tabla Confirmación Entrega</option>
                </select>
                <i className="fas fa-chevron-down absolute right-3 top-3 text-gray-400 pointer-events-none text-xs"></i>
              </div>
            </div>

            <div className="w-full md:w-auto">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Inicio</label>
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium bg-gray-50 text-gray-900"
              />
            </div>

            <div className="w-full md:w-auto">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Fecha Fin</label>
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full p-2 border-2 border-gray-100 rounded-lg focus:border-blue-800 outline-none text-sm font-medium bg-gray-50 text-gray-900"
              />
            </div>

            <button 
              onClick={generateReport}
              disabled={isGeneratingReport}
              className="w-full md:w-auto px-6 py-2.5 bg-green-600 hover:bg-green-700 text-white font-bold rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {isGeneratingReport ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-download"></i>}
              Descargar
            </button>
          </div>

          <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
             <p className="text-[10px] text-blue-800 italic">
               <i className="fas fa-info-circle mr-1"></i>
               {reportType === 'orders' && "Descarga datos generales de la tabla 'Pedido' (Cliente, Monto, Estado)."}
               {reportType === 'shipments' && "Descarga datos de la tabla 'Embarque' (Unidad, Placas, Chofer)."}
               {reportType === 'evidence' && "Descarga datos de la tabla 'Evidencias' (Confirmación de entregas fallidas)."}
             </p>
          </div>
        </div>
      </div>

      {/* Table Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
            <i className="fas fa-list-check text-blue-800"></i>
            Bitácora de Pedidos
          </h3>
          <button 
            onClick={fetchTickets}
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 px-4 py-2 rounded-lg text-sm font-bold transition-colors"
          >
            <i className="fas fa-sync mr-2"></i>Actualizar
          </button>
        </div>
        <div className="overflow-x-auto -mx-6">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
              <tr>
                <th className="px-6 py-4">Folio / Ticket</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {tickets.map((ticket) => (
                <tr key={ticket.folio} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-black text-gray-900">{ticket.no_tiket}</div>
                    <div className="font-mono text-[10px] text-gray-400">{ticket.folio.substring(0,8)}...</div>
                  </td>
                  <td className="px-6 py-4 text-gray-600 font-medium text-xs">
                    {ticket.nombre_cliente.split('|')[0].substring(0,30)}
                  </td>
                  <td className="px-6 py-4 text-gray-500 text-xs">${ticket.monto_de_compra}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${getStatusColor(ticket.estado)}`}>
                      {ticket.estado}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right flex justify-end gap-2">
                    <button 
                      onClick={() => setEditingTicket({ ...ticket })}
                      className="text-blue-800 hover:text-blue-900 p-2 rounded-lg hover:bg-blue-100 transition-all shadow-sm border border-blue-100"
                      title="Editar Pedido"
                    >
                      <i className="fas fa-edit"></i>
                    </button>
                    <button 
                      onClick={() => deleteTicket(ticket.folio)}
                      className="text-red-500 hover:text-red-700 p-2 rounded-lg hover:bg-red-50 transition-all shadow-sm border border-red-100"
                      title="Eliminar Pedido"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Stats Summary Section */}
      <div className="bg-white p-6 rounded-2xl shadow-md border border-gray-100">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-gray-800">
          <i className="fas fa-chart-pie text-red-600"></i>
          Resumen Logístico
        </h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
              <XAxis type="number" hide />
              <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={100} />
              <Tooltip 
                cursor={{fill: 'transparent'}}
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} 
              />
              <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={40}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Edit Modal */}
      {editingTicket && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-slideUp">
            <div className="bg-blue-800 text-white p-6 flex justify-between items-center">
              <div>
                <h4 className="text-xl font-black">Editar Pedido</h4>
                <p className="text-blue-200 text-xs">Modificando: {editingTicket.no_tiket}</p>
              </div>
              <button onClick={() => setEditingTicket(null)} className="text-blue-300 hover:text-white transition-colors">
                <i className="fas fa-times text-2xl"></i>
              </button>
            </div>

            <form onSubmit={updateTicket} className="p-6 space-y-4">

              {/* Ticket No Input */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">No. Ticket</label>
                <input 
                  type="text" 
                  value={editingTicket.no_tiket}
                  onChange={e => setEditingTicket({ ...editingTicket, no_tiket: e.target.value })}
                  className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all font-bold bg-gray-50 text-gray-900"
                />
              </div>

              {/* Amount Input */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Monto de Compra</label>
                <div className="relative">
                  <span className="absolute left-3 top-3 text-gray-400 font-bold">$</span>
                  <input 
                    type="number" 
                    value={editingTicket.monto_de_compra}
                    onChange={e => setEditingTicket({ ...editingTicket, monto_de_compra: parseFloat(e.target.value) || 0 })}
                    className="w-full pl-8 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all font-bold bg-gray-50 text-gray-900"
                  />
                </div>
              </div>

              {/* Status Select */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Estado del Pedido</label>
                <div className="relative">
                  <select 
                    value={editingTicket.estado}
                    onChange={e => setEditingTicket({ ...editingTicket, estado: e.target.value })}
                    className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 outline-none transition-all appearance-none bg-gray-50 font-medium text-gray-900"
                  >
                    <option value={TicketStatus.PENDING}>Pendiente</option>
                    <option value={TicketStatus.IN_TRANSIT}>En Tránsito</option>
                    <option value={TicketStatus.DELIVERED}>Entregado</option>
                    <option value={TicketStatus.NOT_FOUND}>No Encontrado</option>
                  </select>
                  <i className="fas fa-chevron-down absolute right-4 top-4 text-gray-400 pointer-events-none"></i>
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="button"
                  onClick={() => setEditingTicket(null)}
                  className="flex-1 py-3 px-4 bg-gray-100 text-gray-600 font-bold rounded-xl hover:bg-gray-200 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 px-4 bg-blue-800 text-white font-bold rounded-xl hover:bg-blue-900 shadow-lg shadow-blue-200 transition-all"
                >
                  Guardar Cambios
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Pedido, TicketStatus } from '../types';

const ShipmentView: React.FC = () => {
  const [activeOrders, setActiveOrders] = useState<Pedido[]>([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    folio: '',
    unit: '',
    plates: '',
    driver: ''
  });

  // Stores the order to be printed
  const [printOrder, setPrintOrder] = useState<Pedido | null>(null);
  // Controls if we show the success/action panel instead of the form
  const [showActions, setShowActions] = useState(false);

  // Fetch pending orders on mount and subscribe to changes
  useEffect(() => {
    fetchPendingOrders();

    const channel = supabase
      .channel('pedido-updates')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'pedido' },
        () => fetchPendingOrders()
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const fetchPendingOrders = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('pedido')
        .select('*')
        .eq('estado', TicketStatus.PENDING)
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (data) setActiveOrders(data);
    } catch (error) {
      console.error("Error fetching orders:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field: string, value: string) => {
    if (field === 'unit' || field === 'plates') {
      if (!/^[a-zA-Z0-9\s-]*$/.test(value)) return;
    }
    if (field === 'driver') {
      if (!/^[a-zA-Z\s]*$/.test(value)) return;
    }
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.folio || !formData.unit || !formData.plates || !formData.driver) {
      alert("Todos los campos son obligatorios");
      return;
    }

    try {
      const orderToPrint = activeOrders.find(o => o.folio === formData.folio);
      if (!orderToPrint) {
        alert("Error: No se encontró la información del pedido para imprimir.");
        return;
      }

      const { error: updateError } = await supabase
        .from('pedido')
        .update({ estado: TicketStatus.IN_TRANSIT })
        .eq('folio', formData.folio);

      if (updateError) throw updateError;

      // FIX: Added 'folio' to the insert payload to link shipment with order
      const { error: insertError } = await supabase
        .from('embarque')
        .insert([{
            folio: formData.folio,
            unidad: formData.unit,
            placas: formData.plates,
            chofer: formData.driver
        }]);

      if (insertError) throw insertError;

      setPrintOrder({
        ...orderToPrint,
        tempUnit: formData.unit,
        tempDriver: formData.driver
      });

      setFormData({ folio: '', unit: '', plates: '', driver: '' });
      setShowActions(true);
      fetchPendingOrders();

    } catch (error: any) {
      console.error("Error saving shipment:", error);
      alert("Error al guardar el embarque: " + error.message);
    }
  };

  const handleDownloadPDF = () => {
    if (!printOrder) return;

    // Use the specific ID of the ticket content container
    const element = document.getElementById('ticket-content');
    if (!element) {
      alert("No se encontró el ticket para generar PDF");
      return;
    }

    // Access html2pdf from window (loaded via script tag in index.html)
    // @ts-ignore
    const html2pdf = window.html2pdf;

    if (!html2pdf) {
      alert("Librería PDF no cargada. Por favor recargue la página.");
      return;
    }

    const opt = {
      margin: 2,
      filename: `Embarque_${printOrder.no_tiket}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: [80, 200], orientation: 'portrait' }
    };

    html2pdf().set(opt).from(element).save();
  };

  const handleNewShipment = () => {
    setPrintOrder(null);
    setShowActions(false);
  };

  return (
    <div className="animate-fadeIn pb-10">

      {/* UI WRAPPER */}
      <div id="shipment-ui">
        {!showActions ? (
          /* --- Main Form UI --- */
          <div className="bg-white p-6 rounded-2xl shadow-xl border-t-4 border-blue-800 max-w-2xl mx-auto">
            <div className="flex items-center gap-4 mb-6 border-b border-gray-100 pb-4">
              <div className="p-3 bg-blue-50 text-blue-800 rounded-xl">
                <i className="fas fa-shipping-fast text-2xl"></i>
              </div>
              <div>
                <h2 className="text-2xl font-black text-gray-800">Generar Embarque</h2>
                <p className="text-sm text-gray-500">Asignación de unidad y chofer</p>
              </div>
            </div>

            <form onSubmit={handleSave} className="space-y-5">
              {/* Folio Selection */}
              <div className="space-y-1">
                <label className="block text-xs font-bold text-gray-600 uppercase">
                  Seleccionar Pedido Pendiente {loading && <i className="fas fa-spinner fa-spin ml-2"></i>}
                </label>
                <div className="relative">
                  <i className="fas fa-list-ol absolute left-4 top-4 text-gray-400"></i>
                  <select 
                    value={formData.folio}
                    onChange={(e) => handleChange('folio', e.target.value)}
                    className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold bg-gray-50 text-gray-900 appearance-none"
                  >
                    <option value="">-- Seleccione un Pedido --</option>
                    {activeOrders.map(order => (
                      <option key={order.folio} value={order.folio}>
                        {order.no_tiket} - {order.nombre_cliente.substring(0, 25)}...
                      </option>
                    ))}
                  </select>
                </div>
                {formData.folio && activeOrders.find(o => o.folio === formData.folio) && (
                  <p className="text-xs text-blue-600 font-bold ml-2 mt-1 break-words">
                    <i className="fas fa-check-circle mr-1"></i> 
                    Cliente: {activeOrders.find(o => o.folio === formData.folio)?.nombre_cliente}
                  </p>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                {/* Unit */}
                <div className="space-y-1">
                  <label className="block text-xs font-bold text-gray-600 uppercase">Unidad (Vehículo)</label>
                  <div className="relative">
                    <i className="fas fa-truck-pickup absolute left-4 top-4 text-gray-400"></i>
                    <input 
                      type="text" 
                      value={formData.unit}
                      onChange={(e) => handleChange('unit', e.target.value)}
                      placeholder="Ejem: Nissan NP300"
                      className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold uppercase bg-gray-50 text-gray-900"
                    />
                  </div>
                </div>

                {/* Plates */}
                <div className="space-y-1">
                  <label className="block text-xs font-bold text-gray-600 uppercase">Placas</label>
                  <div className="relative">
                    <i className="fas fa-minus-circle absolute left-4 top-4 text-gray-400"></i>
                    <input 
                      type="text" 
                      value={formData.plates}
                      onChange={(e) => handleChange('plates', e.target.value)}
                      placeholder="ABC-123-D"
                      className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-bold uppercase bg-gray-50 text-gray-900"
                    />
                  </div>
                </div>
              </div>

              {/* Driver */}
              <div className="space-y-1">
                <label className="block text-xs font-bold text-gray-600 uppercase">Nombre del Chofer <span className="text-blue-500 text-[10px]">(Solo Letras)</span></label>
                <div className="relative">
                  <i className="fas fa-user-friends absolute left-4 top-4 text-gray-400"></i>
                  <input 
                    type="text" 
                    value={formData.driver}
                    onChange={(e) => handleChange('driver', e.target.value)}
                    placeholder="Nombre Completo del Operador"
                    className="w-full pl-10 p-3 border-2 border-gray-100 rounded-xl focus:border-blue-800 focus:ring-0 outline-none transition-all font-medium bg-gray-50 text-gray-900"
                  />
                </div>
              </div>

              <div className="pt-4">
                <button 
                  type="submit"
                  className="w-full bg-blue-800 hover:bg-blue-900 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-blue-200 transform active:scale-[0.98] flex items-center justify-center gap-2 border-b-4 border-blue-950"
                >
                  <i className="fas fa-check-circle"></i>
                  Generar y Guardar Embarque
                </button>
              </div>
            </form>
          </div>
        ) : (
          /* --- Action Panel (After Success) --- */
          <div className="animate-fadeIn max-w-md mx-auto">
            <div className="bg-white rounded-3xl shadow-2xl p-8 border-t-8 border-green-500 text-center">
              <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                <i className="fas fa-check text-4xl text-green-600"></i>
              </div>

              <h3 className="text-2xl font-black text-gray-800 mb-2">¡Embarque Generado!</h3>
              <p className="text-gray-500 mb-6 text-sm">El pedido ha pasado a estado <strong>"En Tránsito"</strong>.</p>

              <div className="space-y-3">
                <button 
                  onClick={handleDownloadPDF}
                  className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2"
                >
                  <i className="fas fa-file-pdf"></i>
                  Descargar PDF
                </button>

                <div className="border-t border-gray-100 my-4 pt-4">
                  <button 
                    onClick={handleNewShipment}
                    className="w-full bg-white border-2 border-gray-200 hover:bg-gray-50 text-gray-600 font-bold py-3 rounded-xl transition-all"
                  >
                    <i className="fas fa-plus mr-2"></i>
                    Nuevo Embarque
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* --- Print Container --- */}
      {/* Hidden container, used as source for html2pdf */}
      {printOrder && (
        <div id="print-container" className="hidden">
           {/* Inner content for PDF */}
          <div 
            id="ticket-content"
            className="w-[80mm] mx-auto bg-white p-2 font-mono text-black"
          >
            <div className="text-center mb-4 border-b-2 border-dashed border-black pb-2">
              <h1 className="font-bold text-xl uppercase">Ferre Don Nico</h1>
              <p className="text-[10px] mt-1">Jilotepec de Molina Enríquez</p>
              <p className="mt-2 font-black text-sm border-2 border-black inline-block px-2 py-1">EMBARQUE DE SALIDA</p>
